import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Calendar, Users, Scissors, 
  TrendingUp, Award, Settings, LogOut, 
  Plus, CheckCircle2, DollarSign, Clock, Sparkles,
  Trash2, BellRing, Camera, User as UserIcon,
  Check, Undo2, AlertTriangle, Wallet, Receipt,
  MessageSquare, KeyRound, Smartphone, ShieldCheck,
  Edit3, Save, X, Send, Gift, Target, Zap, Box, Minus,
  Search, Phone, Image as ImageIcon, Briefcase,
  ExternalLink, Crown, Star, Eye, EyeOff, ShoppingCart, Link as LinkIcon,
  Megaphone, Wand2, MessageCircle, ChevronUp, ChevronDown, ChevronsUp, ChevronsDown,
  Beer, Wine, CupSoda, Coffee, UserSearch, History, ArrowRightLeft, Upload,
  BarChart3, Activity
} from 'lucide-react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, 
  Tooltip, ResponsiveContainer, BarChart, Bar 
} from 'recharts';

import { Button, Input, Card, Badge } from './components/UI';
import { StorageService } from './services/storage';
import { GeminiService } from './services/gemini';
import { Client, Service, Appointment, UserSession, Tab, Material, Drink, Sale } from './types';

interface BalanceAdjustment {
  id: string;
  amount: number;
  reason: string;
  date: string;
}

const DEFAULT_SERVICES: Service[] = [
  { id: '1', name: 'Corte Social', price: 35, duration: 30 },
  { id: '2', name: 'Degradê Especial', price: 45, duration: 45 },
  { id: '3', name: 'Barba Terápia', price: 25, duration: 25 },
];

const DEFAULT_PROFILE_IMG = "https://images.unsplash.com/photo-1621605815971-fbc98d665033?q=80&w=400&h=400&auto=format&fit=crop";

const LogoElite = ({ className = "h-12 w-12" }: { className?: string }) => (
  <div className={`relative flex items-center justify-center ${className}`}>
    <div className="absolute inset-0 flex items-center justify-center">
      <Scissors className="text-elite-red-500 animate-scissors-left -translate-x-1" size={32} />
      <Scissors className="text-elite-red-500 animate-scissors-right translate-x-1" size={32} />
    </div>
  </div>
);

const App: React.FC = () => {
  // Authentication & Session
  const [session, setSession] = useState<UserSession | null>(() => StorageService.get<UserSession>('session'));
  const [isAuthenticated, setIsAuthenticated] = useState(!!session);
  const [authMode, setAuthMode] = useState<'login' | 'register' | 'recovery'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  // Lazy initialize state
  const getInitialData = <T,>(key: string, defaultValue: T): T => {
    if (!session) return defaultValue;
    return StorageService.get<T>(`${session.username}_${key}`) || defaultValue;
  };

  const [activeTab, setActiveTab] = useState<Tab>(Tab.Dashboard);
  const [financeSubTab, setFinanceSubTab] = useState<'paid' | 'pending' | 'adjustments'>('pending');

  const [clients, setClients] = useState<Client[]>(() => getInitialData('clients', []));
  const [services, setServices] = useState<Service[]>(() => getInitialData('services', DEFAULT_SERVICES));
  const [materials, setMaterials] = useState<Material[]>(() => getInitialData('materials', []));
  const [drinks, setDrinks] = useState<Drink[]>(() => getInitialData('drinks', []));
  const [sales, setSales] = useState<Sale[]>(() => getInitialData('sales', []));
  const [appointments, setAppointments] = useState<Appointment[]>(() => getInitialData('appointments', []));
  const [adjustments, setAdjustments] = useState<BalanceAdjustment[]>(() => getInitialData('adjustments', []));
  const [marketingMsg, setMarketingMsg] = useState(() => getInitialData('marketing_msg', ""));
  const [campaignGoal, setCampaignGoal] = useState(() => getInitialData('campaign_goal', ""));

  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [agendaSearchTerm, setAgendaSearchTerm] = useState("");
  const [aptClientSearch, setAptClientSearch] = useState("");
  const [selectedAptClient, setSelectedAptClient] = useState<Client | null>(null);
  const [showAptResults, setShowAptResults] = useState(false);

  const [isAdjustingBalance, setIsAdjustingBalance] = useState(false);
  const [manualAdjustmentForm, setManualAdjustmentForm] = useState({ amount: '', reason: '' });
  const [editingClientId, setEditingClientId] = useState<string | null>(null);
  const [clientForm, setClientForm] = useState({ name: '', phone: '' });
  const [editingServiceId, setEditingServiceId] = useState<string | null>(null);
  const [serviceForm, setServiceForm] = useState({ name: '', price: '' });
  const [drinkForm, setDrinkForm] = useState({ name: '', price: '', stock: '' });
  const [editingMaterialId, setEditingMaterialId] = useState<string | null>(null);
  const [materialForm, setMaterialForm] = useState({ name: '', quantity: '', minQuantity: '', supplierLink: '' });

  const [isPrivacyMode, setIsPrivacyMode] = useState(false);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [isGeneratingMessage, setIsGeneratingMessage] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
    if (session && isAuthenticated) {
      setIsSaving(true);
      const data = {
        clients, services, materials, drinks, sales, appointments, adjustments, marketingMsg, campaignGoal
      };
      Object.entries(data).forEach(([key, value]) => {
        StorageService.set(`${session.username}_${key}`, value);
      });
      const timer = setTimeout(() => setIsSaving(false), 500);
      return () => clearTimeout(timer);
    }
  }, [clients, services, materials, drinks, sales, appointments, adjustments, marketingMsg, campaignGoal, session, isAuthenticated]);

  const stats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const monthPrefix = today.substring(0, 7);

    const compApts = appointments.filter(a => a.completed);
    const todayApts = compApts.filter(a => a.date === today);
    const monthApts = compApts.filter(a => a.date.startsWith(monthPrefix));

    const serviceDailyRev = todayApts.filter(a => a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0);
    const serviceMonthlyRev = monthApts.filter(a => a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0);

    const todaySales = sales.filter(s => s.date === today);
    const monthSales = sales.filter(s => s.date.startsWith(monthPrefix));
    const salesDailyRev = todaySales.reduce((acc, s) => acc + s.price, 0);
    const salesMonthlyRev = monthSales.reduce((acc, s) => acc + s.price, 0);

    const todayAdjusts = adjustments.filter(adj => adj.date === today);
    const monthAdjusts = adjustments.filter(adj => adj.date.startsWith(monthPrefix));
    const adjustsDaily = todayAdjusts.reduce((acc, a) => acc + a.amount, 0);
    const adjustsMonthly = monthAdjusts.reduce((acc, a) => acc + a.amount, 0);

    const dailyRev = serviceDailyRev + salesDailyRev + adjustsDaily;
    const monthlyRev = serviceMonthlyRev + salesMonthlyRev + adjustsMonthly;

    // Chart Data Generation (Last 7 days)
    const chartData = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toISOString().split('T')[0];
      const dailyApts = compApts.filter(a => a.date === dateStr && a.paid);
      const dailySales = sales.filter(s => s.date === dateStr);
      const dailyAdjusts = adjustments.filter(a => a.date === dateStr);

      const rev = dailyApts.reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0) +
                  dailySales.reduce((acc, s) => acc + s.price, 0) +
                  dailyAdjusts.reduce((acc, a) => acc + a.amount, 0);

      return { 
        name: d.toLocaleDateString('pt-BR', { weekday: 'short' }), 
        receita: Math.max(0, rev),
        data: dateStr
      };
    });

    return { 
      dailyRev, monthlyRev, todayCuts: todayApts.length, monthlyCuts: monthApts.length,
      goalPercent: Math.min(Math.round((monthlyRev / (session?.monthlyGoal || 5000)) * 100), 100),
      chartData
    };
  }, [appointments, services, sales, adjustments, session?.monthlyGoal]);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);
    const f = new FormData(e.target as HTMLFormElement);
    const user = (f.get('username') as string)?.toLowerCase().trim();
    const pass = f.get('password') as string;
    const shop = f.get('shopName') as string;

    if (authMode === 'register') {
      StorageService.set(`user_auth_${user}`, { username: user, password: pass, shopName: shop, phone: f.get('phone'), profileImage: DEFAULT_PROFILE_IMG, monthlyGoal: 5000 });
      setAuthMode('login');
      showToast("Unidade registrada!");
      return;
    }

    const stored = StorageService.get<any>(`user_auth_${user}`);
    if (!stored || stored.password !== pass) {
      setAuthError("Dados inválidos.");
      return;
    }

    const sess: UserSession = { 
      shopName: stored.shopName, 
      username: stored.username, 
      phone: stored.phone, 
      profileImage: stored.profileImage || DEFAULT_PROFILE_IMG,
      monthlyGoal: stored.monthlyGoal || 5000
    };
    StorageService.set('session', sess);
    setSession(sess);
    setIsAuthenticated(true);
    window.location.reload(); // Refresh to ensure clean state
  };

  const toggleCompleteFlow = (id: string, paidStatus: boolean) => {
    setAppointments(prev => prev.map(apt => {
      if (apt.id === id) {
        const s = services.find(sv => sv.id === apt.serviceId);
        setClients(prevC => prevC.map(c => {
          if (c.id === apt.clientId) {
            const price = s?.price || 0;
            return { ...c, loyaltyPoints: paidStatus ? c.loyaltyPoints + 1 : c.loyaltyPoints, totalSpent: c.totalSpent + (paidStatus ? price : 0) };
          }
          return c;
        }));
        return { ...apt, completed: true, paid: paidStatus };
      }
      return apt;
    }));
    showToast(paidStatus ? "Pagamento confirmado!" : "Finalizado (Pendente)");
  };

  const sellDrink = (drink: Drink) => {
    if (drink.stock <= 0) return showToast("Sem estoque!", "error");
    const newSale: Sale = {
      id: Date.now().toString(),
      itemId: drink.id,
      itemName: drink.name,
      price: drink.price,
      date: new Date().toISOString().split('T')[0]
    };
    setSales(prev => [...prev, newSale]);
    setDrinks(prev => prev.map(d => d.id === drink.id ? { ...d, stock: d.stock - 1 } : d));
    showToast("Venda realizada com sucesso!");
  };

  const formatCurrency = (value: number) => {
    if (isPrivacyMode) return '••••••';
    return `R$ ${value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;
  };

  const filteredAppointments = useMemo(() => {
    return appointments
      .filter(a => a.date === selectedDate && !a.completed)
      .sort((a,b) => a.time.localeCompare(b.time));
  }, [appointments, selectedDate]);

  if (!isAuthenticated) return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="w-full max-w-md space-y-8 animate-in fade-in zoom-in duration-500">
        <div className="text-center">
          <LogoElite className="mx-auto h-24 w-24 mb-4" />
          <h2 className="text-4xl font-black text-white uppercase tracking-tighter">Elite <span className="text-elite-red-500">Barber</span></h2>
          <p className="text-elite-cyan-400 text-[9px] font-black uppercase tracking-[0.4em] mt-2">The Ultimate Management Experience</p>
        </div>
        <Card className="glass-card">
          <form className="space-y-4" onSubmit={handleAuth}>
            {authError && <p className="text-[10px] text-red-500 font-black uppercase text-center bg-red-500/10 p-2 rounded-lg">{authError}</p>}
            {authMode === 'register' && (
              <>
                <Input label="NOME DA BARBEARIA" name="shopName" placeholder="EX: BARBER SHOP" required />
                <Input label="WHATSAPP" name="phone" placeholder="(11) 99999-9999" required />
              </>
            )}
            <Input label="USUÁRIO" name="username" placeholder="admin" required />
            <Input label="SENHA" name="password" type="password" placeholder="••••••••" required />
            <Button type="submit" className="w-full py-4">{authMode === 'login' ? 'Acessar Sistema' : 'Criar Unidade'}</Button>
            <button type="button" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')} className="w-full text-[10px] text-elite-red-500 font-black uppercase tracking-widest hover:text-white transition-colors">
              {authMode === 'login' ? 'Quero registrar minha barbearia' : 'Voltar para o Login'}
            </button>
          </form>
        </Card>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen text-slate-100 flex overflow-hidden">
      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-950/80 backdrop-blur-2xl border-r border-elite-lilac-950/30 transition-all duration-300 lg:relative ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:w-20 lg:translate-x-0'}`}>
        <div className="h-full flex flex-col p-6">
          <div className="mb-10 flex items-center gap-4 overflow-hidden">
            <LogoElite className="h-10 w-10 min-w-[40px]" />
            {isSidebarOpen && <div className="truncate"><h1 className="text-[10px] font-black text-white uppercase tracking-widest">Elite Barber System</h1><p className="text-[8px] text-elite-red-500 font-black uppercase truncate">{session?.shopName}</p></div>}
          </div>
          <nav className="flex-1 space-y-1.5">
            {[
              { id: Tab.Dashboard, icon: LayoutDashboard, label: 'Painel' },
              { id: Tab.Agenda, icon: Calendar, label: 'Agenda' },
              { id: Tab.Clients, icon: Users, label: 'Clientes' },
              { id: Tab.Loyalty, icon: Award, label: 'Fidelidade' },
              { id: Tab.Marketing, icon: Megaphone, label: 'Marketing AI' },
              { id: Tab.Services, icon: Scissors, label: 'Serviços' },
              { id: Tab.Drinks, icon: Beer, label: 'Bar' },
              { id: Tab.Inventory, icon: Box, label: 'Estoque' },
              { id: Tab.Finance, icon: TrendingUp, label: 'Financeiro' },
              { id: Tab.Profile, icon: Settings, label: 'Configurações' },
            ].map(item => (
              <button 
                key={item.id} 
                onClick={() => setActiveTab(item.id)} 
                className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === item.id ? 'bg-elite-red-500 text-white shadow-lg shadow-elite-red-900/20' : 'text-slate-500 hover:text-elite-red-400 hover:bg-white/5'}`}
              >
                <item.icon size={18} />
                {isSidebarOpen && <span className="truncate">{item.label}</span>}
              </button>
            ))}
          </nav>
          <button onClick={() => { StorageService.remove('session'); window.location.reload(); }} className="mt-auto flex items-center gap-3 px-4 py-4 text-[10px] font-black uppercase text-red-500 hover:bg-red-500/10 rounded-xl transition-colors">
            <LogOut size={18} />
            {isSidebarOpen && <span>Sair</span>}
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 h-screen overflow-y-auto">
        <header className="sticky top-0 z-40 bg-slate-950/60 backdrop-blur-xl border-b border-white/5 px-8 py-6 flex items-center justify-between">
           <div className="flex items-center gap-4">
              <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-500 hover:text-white transition-colors lg:hidden"><LayoutDashboard size={20}/></button>
              <h2 className="text-xl font-black uppercase tracking-tighter text-white">{activeTab}</h2>
           </div>
           <div className="flex items-center gap-4">
              {isSaving && <Badge variant="cyan" className="animate-pulse">Sincronizando...</Badge>}
              <button onClick={() => setIsPrivacyMode(!isPrivacyMode)} className="p-2.5 bg-slate-900 border border-white/5 rounded-xl text-slate-400 hover:text-elite-cyan-400 transition-all">
                {isPrivacyMode ? <EyeOff size={18}/> : <Eye size={18}/>}
              </button>
              <div className="h-9 w-9 rounded-xl border border-elite-red-500/30 bg-slate-900 flex items-center justify-center overflow-hidden">
                 <img src={session?.profileImage} className="h-full w-full object-cover" />
              </div>
           </div>
        </header>

        <div className="p-8 max-w-7xl mx-auto space-y-8 pb-32">
          {toast && (
            <div className={`fixed bottom-10 right-10 z-[100] px-6 py-4 rounded-2xl text-[10px] font-black uppercase flex items-center gap-3 animate-in slide-in-from-right duration-300 shadow-2xl ${toast.type === 'error' ? 'bg-red-600 text-white' : 'bg-elite-cyan-500 text-black'}`}>
              {toast.type === 'error' ? <AlertTriangle size={16}/> : <CheckCircle2 size={16}/>} {toast.message}
            </div>
          )}

          {activeTab === Tab.Dashboard && (
            <div className="space-y-8 animate-in fade-in duration-500">
              {/* Main Revenue Card */}
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 relative overflow-hidden bg-slate-900/60 border border-white/5 p-10 rounded-[32px] shadow-2xl">
                   <div className="relative z-10">
                      <div className="flex items-center justify-between mb-8">
                        <div>
                           <p className="text-[11px] font-black text-elite-cyan-400 uppercase tracking-widest mb-1 flex items-center gap-2"><TrendingUp size={14}/> Receita Últimos 7 Dias</p>
                           <h3 className="text-6xl font-black text-white tracking-tighter leading-none">{formatCurrency(stats.monthlyRev)}</h3>
                        </div>
                        <div className="text-right">
                           <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Status da Meta</p>
                           <Badge variant={stats.goalPercent >= 100 ? 'success' : 'lilac'}>{stats.goalPercent}% DA META</Badge>
                        </div>
                      </div>

                      <div className="h-[250px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                          <AreaChart data={stats.chartData}>
                            <defs>
                              <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#06b6d4" stopOpacity={0.3}/>
                                <stop offset="95%" stopColor="#06b6d4" stopOpacity={0}/>
                              </linearGradient>
                            </defs>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
                            <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 'bold'}} />
                            <Tooltip 
                              contentStyle={{ backgroundColor: '#020617', border: '1px solid #1e293b', borderRadius: '12px' }}
                              itemStyle={{ color: '#06b6d4', fontWeight: 'bold', fontSize: '12px' }}
                            />
                            <Area type="monotone" dataKey="receita" stroke="#06b6d4" strokeWidth={3} fillOpacity={1} fill="url(#colorRev)" />
                          </AreaChart>
                        </ResponsiveContainer>
                      </div>
                   </div>
                </div>

                <div className="space-y-6">
                   <div className="bg-slate-900/60 border border-white/5 p-8 rounded-[32px] shadow-xl">
                      <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4 flex items-center gap-2"><Target size={14}/> Objetivo do Mês</p>
                      <div className="flex items-end justify-between mb-3">
                        <span className="text-3xl font-black text-white">{formatCurrency(session?.monthlyGoal || 5000)}</span>
                        <span className="text-sm font-black text-elite-cyan-400">{stats.goalPercent}%</span>
                      </div>
                      <div className="h-3 w-full bg-slate-950 rounded-full overflow-hidden mb-6">
                        <div className="h-full bg-elite-cyan-500 rounded-full transition-all duration-1000" style={{ width: `${stats.goalPercent}%` }} />
                      </div>
                      <Button onClick={() => setIsAdjustingBalance(true)} variant="ghost" size="sm" className="w-full">Ajustar Meta</Button>
                   </div>

                   <div className="bg-elite-red-500/10 border border-elite-red-500/20 p-8 rounded-[32px] shadow-xl group hover:bg-elite-red-500/20 transition-all">
                      <p className="text-[10px] font-black text-elite-red-400 uppercase tracking-widest mb-2">Cortes Hoje</p>
                      <div className="flex items-center justify-between">
                         <span className="text-5xl font-black text-white">{isPrivacyMode ? '••' : stats.todayCuts}</span>
                         <div className="h-12 w-12 rounded-2xl bg-elite-red-500 flex items-center justify-center text-white shadow-lg shadow-elite-red-900/40">
                            <Scissors size={24} />
                         </div>
                      </div>
                   </div>
                </div>
              </div>

              {/* Stat Grid */}
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                 {[
                   { l: 'Cortes Mensais', v: isPrivacyMode ? '••' : stats.monthlyCuts, i: <Activity size={18}/>, c: 'text-elite-lilac-400' },
                   { l: 'Ticket Médio', v: formatCurrency(stats.monthlyRev / (stats.monthlyCuts || 1)), i: <DollarSign size={18}/>, c: 'text-emerald-400' },
                   { l: 'Membros VIP', v: clients.length, i: <Crown size={18}/>, c: 'text-amber-400' },
                   { l: 'Gaveta Hoje', v: formatCurrency(stats.dailyRev), i: <Wallet size={18}/>, c: 'text-elite-cyan-400' },
                 ].map((s, i) => (
                   <div key={i} className="bg-slate-900/40 border border-white/5 p-8 rounded-[28px] hover:border-white/10 transition-all">
                      <div className={`mb-4 ${s.c}`}>{s.i}</div>
                      <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-1">{s.l}</p>
                      <p className="text-2xl font-black text-white">{s.v}</p>
                   </div>
                 ))}
              </div>
            </div>
          )}

          {activeTab === Tab.Agenda && (
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 animate-in slide-in-from-bottom duration-500">
               <div className="lg:col-span-1">
                  <Card title="Agendar" icon={<Plus size={16}/>}>
                     <form className="space-y-5" onSubmit={(e) => { e.preventDefault(); handleAgendaSubmit(e); }}>
                        <Input label="DATA" name="d" type="date" defaultValue={selectedDate} required />
                        <Input label="HORÁRIO" name="t" type="time" required />
                        <div className="space-y-2 relative">
                           <label className="text-[10px] font-black text-elite-cyan-400 uppercase tracking-widest ml-1">CLIENTE</label>
                           <input 
                              type="text"
                              placeholder="Buscar..."
                              className="w-full bg-slate-950/40 border border-white/10 focus:border-elite-red-500 rounded-xl px-4 py-3 text-white text-xs font-bold outline-none"
                              value={aptClientSearch}
                              onChange={(e) => { setAptClientSearch(e.target.value); setShowAptResults(true); }}
                           />
                           {showAptResults && aptClientSearchResults.length > 0 && (
                              <div className="absolute z-50 left-0 right-0 mt-2 bg-slate-900 border border-white/10 rounded-xl shadow-2xl overflow-hidden">
                                 {aptClientSearchResults.map(c => (
                                    <button key={c.id} type="button" className="w-full text-left px-4 py-3 hover:bg-white/5 flex flex-col" onClick={() => { setSelectedAptClient(c); setAptClientSearch(c.name); setShowAptResults(false); }}>
                                       <span className="text-[10px] font-black text-white uppercase">{c.name}</span>
                                       <span className="text-[8px] text-slate-500">{c.phone}</span>
                                    </button>
                                 ))}
                              </div>
