                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                     <div className="space-y-5">
                        <Input label="QUAL O OBJETIVO DA CAMPANHA?" value={campaignGoal} onChange={e => setCampaignGoal(e.target.value)} placeholder="Ex: Cupom de 10% para clientes sumidos" />
                        <Button variant="lilac" className="w-full h-14" onClick={async () => {
