                        <textarea className="w-full h-40 bg-slate-950/60 border border-white/10 rounded-[20px] p-6 text-white text-sm font-medium outline-none focus:border-elite-red-500 transition-all shadow-inner" value={marketingMsg} onChange={e => setMarketingMsg(e.target.value)} />
                     </div>
                     <div className="bg-slate-950/40 border border-white/5 rounded-[32px] p-8">
                        <h4 className="font-black uppercase text-[10px] text-elite-cyan-400 tracking-widest mb-6">Lista de Envio ({clients.length})</h4>
