                                 <button onClick={() => {
                                    const msg = marketingMsg.replace('[NOME DO CLIENTE]', c.name);
                                    window.open(`https://wa.me/55${c.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
                                 }} className="p-2 bg-emerald-500/10 text-emerald-500 rounded-lg hover:bg-emerald-500 hover:text-white transition-all"><MessageCircle size={16}/></button>
                              </div>
