               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {services.map(s => (
                    <div key={s.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] hover:border-elite-red-500/30 transition-all group">
                       <div className="flex justify-between items-start mb-6">
                          <h4 className="text-xl font-black text-white uppercase tracking-tight">{s.name}</h4>
                          <div className="flex gap-1">
                             <button onClick={() => { setEditingServiceId(s.id); setServiceForm({name: s.name, price: s.price.toString()}); }} className="p-2 text-slate-700 hover:text-white"><Edit3 size={16}/></button>
                             <button onClick={() => setServices(prev => prev.filter(x => x.id !== s.id))} className="p-2 text-slate-700 hover:text-red-500"><Trash2 size={16}/></button>
                          </div>
                       </div>
                       <p className="text-4xl font-black text-elite-cyan-400">R$ {s.price.toFixed(2)}</p>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {/* Placeholder/Simplified views for remaining tabs to ensure world-class feel */}
          {[Tab.Drinks, Tab.Inventory, Tab.Clients, Tab.Loyalty, Tab.Profile].includes(activeTab) && (
            <div className="text-center p-20 opacity-50 font-black uppercase text-[10px] tracking-widest animate-pulse">
               Carregando Módulo {activeTab}...
               <p className="mt-4 text-elite-red-500">Interface em desenvolvimento de alto nível</p>
               <Button onClick={() => setActiveTab(Tab.Dashboard)} className="mt-8">Voltar ao Painel</Button>
            </div>
          )}

        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Calendar, Users, Scissors, 
  TrendingUp, Award, Settings, LogOut, 
  Plus, CheckCircle2, DollarSign, Clock, Sparkles,
  Trash2, BellRing, Camera, User as UserIcon,
  Check, Undo2, AlertTriangle, Wallet, Receipt,
  MessageSquare, KeyRound, Smartphone, ShieldCheck,
  Edit3, Save, X, Send, Gift, Target, Zap, Box, Minus,
  Search, Phone, Image as ImageIcon, Briefcase,
  ExternalLink, Crown, Star, Eye, EyeOff, ShoppingCart, Link as LinkIcon,
  Megaphone, Wand2, MessageCircle, ChevronUp, ChevronDown, Activity
} from 'lucide-react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, 
  Tooltip, ResponsiveContainer 
} from 'recharts';

import { Button, Input, Card, Badge } from './components/UI';
import { StorageService } from './services/storage';
import { GeminiService } from './services/gemini';
import { Client, Service, Appointment, UserSession, Tab, Material, Drink, Sale } from './types';

interface BalanceAdjustment {
  id: string;
  amount: number;
  reason: string;
  date: string;
}

const DEFAULT_SERVICES: Service[] = [
  { id: '1', name: 'Corte Social', price: 35, duration: 30 },
  { id: '2', name: 'Degradê Especial', price: 45, duration: 45 },
  { id: '3', name: 'Barba Terápia', price: 25, duration: 25 },
];

const DEFAULT_PROFILE_IMG = "https://images.unsplash.com/photo-1621605815971-fbc98d665033?q=80&w=400&h=400&auto=format&fit=crop";

const LogoElite = ({ className = "h-12 w-12" }: { className?: string }) => (
  <div className={`relative flex items-center justify-center ${className}`}>
    <div className="absolute inset-0 flex items-center justify-center">
      <Scissors className="text-elite-red-500 animate-scissors-left -translate-x-1" size={32} />
      <Scissors className="text-elite-red-500 animate-scissors-right translate-x-1" size={32} />
    </div>
  </div>
);

const App: React.FC = () => {
  // Authentication & Session
  const [session, setSession] = useState<UserSession | null>(() => StorageService.get<UserSession>('session'));
  const [isAuthenticated, setIsAuthenticated] = useState(!!session);
  const [authMode, setAuthMode] = useState<'login' | 'register' | 'recovery'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const getInitialData = <T,>(key: string, defaultValue: T): T => {
    if (!session) return defaultValue;
    return StorageService.get<T>(`${session.username}_${key}`) || defaultValue;
  };

  const [activeTab, setActiveTab] = useState<Tab>(Tab.Dashboard);
  const [financeSubTab, setFinanceSubTab] = useState<'paid' | 'pending' | 'adjustments'>('pending');

  const [clients, setClients] = useState<Client[]>(() => getInitialData('clients', []));
  const [services, setServices] = useState<Service[]>(() => getInitialData('services', DEFAULT_SERVICES));
  const [materials, setMaterials] = useState<Material[]>(() => getInitialData('materials', []));
  const [drinks, setDrinks] = useState<Drink[]>(() => getInitialData('drinks', []));
  const [sales, setSales] = useState<Sale[]>(() => getInitialData('sales', []));
  const [appointments, setAppointments] = useState<Appointment[]>(() => getInitialData('appointments', []));
  const [adjustments, setAdjustments] = useState<BalanceAdjustment[]>(() => getInitialData('adjustments', []));
  const [marketingMsg, setMarketingMsg] = useState(() => getInitialData('marketing_msg', ""));
  const [campaignGoal, setCampaignGoal] = useState(() => getInitialData('campaign_goal', ""));

  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [aptClientSearch, setAptClientSearch] = useState("");
  const [selectedAptClient, setSelectedAptClient] = useState<Client | null>(null);
  const [showAptResults, setShowAptResults] = useState(false);

  const [isAdjustingBalance, setIsAdjustingBalance] = useState(false);
  const [manualAdjustmentForm, setManualAdjustmentForm] = useState({ amount: '', reason: '' });
  const [serviceForm, setServiceForm] = useState({ name: '', price: '' });
  const [editingServiceId, setEditingServiceId] = useState<string | null>(null);

  const [isPrivacyMode, setIsPrivacyMode] = useState(false);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [isSaving, setIsSaving] = useState(false);
  const [isGeneratingMessage, setIsGeneratingMessage] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
    if (session && isAuthenticated) {
      setIsSaving(true);
      const data: Record<string, any> = { clients, services, materials, drinks, sales, appointments, adjustments, marketing_msg: marketingMsg, campaign_goal: campaignGoal };
      Object.entries(data).forEach(([k, v]) => StorageService.set(`${session.username}_${k}`, v));
      const timer = setTimeout(() => setIsSaving(false), 500);
      return () => clearTimeout(timer);
    }
  }, [clients, services, materials, drinks, sales, appointments, adjustments, marketingMsg, campaignGoal, session, isAuthenticated]);

  const stats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const monthPrefix = today.substring(0, 7);

    const compApts = appointments.filter(a => a.completed);
    const todayApts = compApts.filter(a => a.date === today);
    const monthApts = compApts.filter(a => a.date.startsWith(monthPrefix));

    const serviceDailyRev = todayApts.filter(a => a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0);
    const serviceMonthlyRev = monthApts.filter(a => a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0);

    const todaySales = sales.filter(s => s.date === today);
    const monthSales = sales.filter(s => s.date.startsWith(monthPrefix));
    const salesDailyRev = todaySales.reduce((acc, s) => acc + s.price, 0);
    const salesMonthlyRev = monthSales.reduce((acc, s) => acc + s.price, 0);

    const todayAdjusts = adjustments.filter(adj => adj.date === today);
    const adjustsDaily = todayAdjusts.reduce((acc, a) => acc + a.amount, 0);

    const dailyRev = serviceDailyRev + salesDailyRev + adjustsDaily;
    const monthlyRev = serviceMonthlyRev + salesMonthlyRev + adjustments.filter(a => a.date.startsWith(monthPrefix)).reduce((acc, a) => acc + a.amount, 0);

    // Gerar dados para o gráfico dos últimos 7 dias
    const chartData = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const dateStr = d.toISOString().split('T')[0];
      const rev = compApts.filter(a => a.date === dateStr && a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0) +
                  sales.filter(s => s.date === dateStr).reduce((acc, s) => acc + s.price, 0);
      return { 
        name: d.toLocaleDateString('pt-BR', { weekday: 'short' }), 
        receita: Math.max(0, rev)
      };
    });

    return { 
      dailyRev, monthlyRev, todayCuts: todayApts.length, monthlyCuts: monthApts.length,
      goalPercent: Math.min(Math.round((monthlyRev / (session?.monthlyGoal || 5000)) * 100), 100),
      chartData
    };
  }, [appointments, services, sales, adjustments, session?.monthlyGoal]);

  const aptClientSearchResults = useMemo(() => {
    if (!aptClientSearch.trim()) return [];
    return clients.filter(c => c.name.toLowerCase().includes(aptClientSearch.toLowerCase())).slice(0, 5);
  }, [aptClientSearch, clients]);

  const filteredAppointments = useMemo(() => {
    return appointments
      .filter(a => a.date === selectedDate && !a.completed)
      .sort((a,b) => a.time.localeCompare(b.time));
  }, [appointments, selectedDate]);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    const user = (f.get('username') as string)?.toLowerCase().trim();
    const pass = f.get('password') as string;

    if (authMode === 'register') {
      StorageService.set(`user_auth_${user}`, { username: user, password: pass, shopName: f.get('shopName'), phone: f.get('phone'), profileImage: DEFAULT_PROFILE_IMG, monthlyGoal: 5000 });
      setAuthMode('login');
      showToast("Unidade registrada!");
      return;
    }

    const stored = StorageService.get<any>(`user_auth_${user}`);
    if (!stored || stored.password !== pass) {
      setAuthError("Dados inválidos.");
      return;
    }

    const sess: UserSession = { shopName: stored.shopName, username: stored.username, phone: stored.phone, profileImage: stored.profileImage || DEFAULT_PROFILE_IMG, monthlyGoal: stored.monthlyGoal || 5000 };
    StorageService.set('session', sess);
    setSession(sess);
    setIsAuthenticated(true);
    window.location.reload();
  };

  const handleAgendaSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    if (!selectedAptClient) return showToast("Selecione um cliente!", "error");

    setAppointments(prev => [...prev, {
      id: Date.now().toString(),
      clientId: selectedAptClient.id,
      serviceId: f.get('s') as string,
      date: f.get('d') as string,
      time: f.get('t') as string,
      completed: false,
      paid: false
    }]);
    setAptClientSearch("");
    setSelectedAptClient(null);
    showToast("Agendado com sucesso!");
  };

  const toggleCompleteFlow = (id: string, paidStatus: boolean) => {
    setAppointments(prev => prev.map(apt => {
      if (apt.id === id) {
        const s = services.find(sv => sv.id === apt.serviceId);
        setClients(prevC => prevC.map(c => {
          if (c.id === apt.clientId) {
            const price = s?.price || 0;
            return { ...c, loyaltyPoints: paidStatus ? c.loyaltyPoints + 1 : c.loyaltyPoints, totalSpent: c.totalSpent + (paidStatus ? price : 0) };
          }
          return c;
        }));
        return { ...apt, completed: true, paid: paidStatus };
      }
      return apt;
    }));
    showToast(paidStatus ? "Atendimento Pago!" : "Atendimento Pendente!");
  };

  const formatCurrency = (v: number) => isPrivacyMode ? '••••' : `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  if (!isAuthenticated) return (
    <div className="min-h-screen flex items-center justify-center p-4">
      <div className="w-full max-w-md space-y-8 animate-in fade-in zoom-in duration-500">
        <div className="text-center">
          <LogoElite className="mx-auto h-24 w-24 mb-4" />
          <h2 className="text-4xl font-black text-white uppercase tracking-tighter italic">Elite <span className="text-elite-red-500">Barber</span></h2>
        </div>
        <Card className="glass-card p-2">
          <form className="space-y-4" onSubmit={handleAuth}>
            {authError && <p className="text-[10px] text-red-500 font-black uppercase text-center bg-red-500/10 p-2 rounded-lg">{authError}</p>}
            {authMode === 'register' && (
              <>
                <Input label="NOME DA BARBEARIA" name="shopName" placeholder="EX: BARBER SHOP" required />
                <Input label="WHATSAPP" name="phone" placeholder="(11) 99999-9999" required />
              </>
            )}
            <Input label="USUÁRIO" name="username" placeholder="admin" required />
            <Input label="SENHA" name="password" type="password" placeholder="••••••••" required />
            <Button type="submit" className="w-full py-4">{authMode === 'login' ? 'Entrar' : 'Criar Conta'}</Button>
            <button type="button" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')} className="w-full text-[10px] text-slate-500 font-black uppercase tracking-widest hover:text-elite-red-500 transition-colors">
              {authMode === 'login' ? 'Registrar Unidade' : 'Já tenho conta'}
            </button>
          </form>
        </Card>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen text-slate-100 flex overflow-hidden">
      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-950/90 backdrop-blur-2xl border-r border-white/5 transition-all duration-300 lg:relative ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:w-20 lg:translate-x-0'}`}>
        <div className="h-full flex flex-col p-6">
          <div className="mb-10 flex items-center gap-4 overflow-hidden">
            <LogoElite className="h-10 w-10 min-w-[40px]" />
            {isSidebarOpen && <div className="truncate"><h1 className="text-[10px] font-black text-white uppercase tracking-widest">Barbearia Elite</h1><p className="text-[8px] text-elite-red-500 font-black uppercase truncate">{session?.shopName}</p></div>}
          </div>
          <nav className="flex-1 space-y-1.5">
            {[
              { id: Tab.Dashboard, icon: LayoutDashboard, label: 'Painel' },
              { id: Tab.Agenda, icon: Calendar, label: 'Agenda' },
              { id: Tab.Clients, icon: Users, label: 'Clientes' },
              { id: Tab.Finance, icon: TrendingUp, label: 'Financeiro' },
              { id: Tab.Loyalty, icon: Award, label: 'Fidelidade' },
              { id: Tab.Marketing, icon: Megaphone, label: 'Marketing' },
              { id: Tab.Services, icon: Scissors, label: 'Serviços' },
            ].map(item => (
              <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center gap-3 px-4 py-3.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === item.id ? 'bg-elite-red-500 text-white shadow-xl shadow-elite-red-900/40' : 'text-slate-500 hover:text-elite-red-500 hover:bg-white/5'}`}>
                <item.icon size={18} />
                {isSidebarOpen && <span>{item.label}</span>}
              </button>
            ))}
          </nav>
          <button onClick={() => { StorageService.remove('session'); window.location.reload(); }} className="mt-auto flex items-center gap-3 px-4 py-4 text-[10px] font-black uppercase text-red-500 hover:bg-red-500/10 rounded-xl transition-colors">
            <LogOut size={18} />
            {isSidebarOpen && <span>Sair</span>}
          </button>
        </div>
      </aside>

      <main className="flex-1 h-screen overflow-y-auto">
        <header className="sticky top-0 z-40 bg-slate-950/60 backdrop-blur-xl border-b border-white/5 px-8 py-6 flex items-center justify-between">
           <div className="flex items-center gap-4">
              <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-500 hover:text-white transition-colors lg:hidden"><LayoutDashboard size={20}/></button>
              <h2 className="text-xl font-black uppercase tracking-widest text-white">{activeTab}</h2>
           </div>
           <div className="flex items-center gap-4">
              {isSaving && <Badge variant="cyan" className="animate-pulse">Sincronizando</Badge>}
              <button onClick={() => setIsPrivacyMode(!isPrivacyMode)} className="p-2.5 bg-slate-900 border border-white/5 rounded-xl text-slate-400 hover:text-elite-cyan-400">
                {isPrivacyMode ? <EyeOff size={18}/> : <Eye size={18}/>}
              </button>
              <div className="h-9 w-9 rounded-xl border border-elite-red-500/30 bg-slate-900 flex items-center justify-center overflow-hidden">
                 <img src={session?.profileImage} className="h-full w-full object-cover" />
              </div>
           </div>
        </header>

        <div className="p-8 max-w-7xl mx-auto space-y-8 pb-32">
          {toast && (
            <div className={`fixed bottom-10 right-10 z-[100] px-6 py-4 rounded-2xl text-[10px] font-black uppercase flex items-center gap-3 animate-in slide-in-from-right duration-300 shadow-2xl ${toast.type === 'error' ? 'bg-red-600 text-white' : 'bg-elite-cyan-500 text-black'}`}>
              {toast.type === 'error' ? <AlertTriangle size={16}/> : <CheckCircle2 size={16}/>} {toast.message}
            </div>
          )}

          {activeTab === Tab.Dashboard && (
            <div className="space-y-8 animate-in fade-in duration-500">
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 relative overflow-hidden bg-slate-900/40 border border-white/5 p-10 rounded-[32px] shadow-2xl">
                   <div className="relative z-10">
                      <div className="flex items-center justify-between mb-8">
                        <div>
                           <p className="text-[11px] font-black text-elite-cyan-400 uppercase tracking-widest mb-1">Receita Semanal</p>
                           <h3 className="text-5xl font-black text-white tracking-tighter">{formatCurrency(stats.monthlyRev)}</h3>
                        </div>
                        <Badge variant={stats.goalPercent >= 100 ? 'success' : 'lilac'}>{stats.goalPercent}% DA META</Badge>
                      </div>
                      <div className="h-[200px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                          <AreaChart data={stats.chartData}>
                            <defs>
                              <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#06b6d4" stopOpacity={0.3}/>
                                <stop offset="95%" stopColor="#06b6d4" stopOpacity={0}/>
                              </linearGradient>
                            </defs>
                            <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
                            <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10}} />
                            <Tooltip contentStyle={{ backgroundColor: '#020617', border: 'none', borderRadius: '12px', fontSize: '10px', fontWeight: 'bold' }} />
                            <Area type="monotone" dataKey="receita" stroke="#06b6d4" strokeWidth={3} fillOpacity={1} fill="url(#colorRev)" />
                          </AreaChart>
                        </ResponsiveContainer>
                      </div>
                   </div>
                </div>

                <div className="space-y-6">
                   <div className="bg-slate-900/60 border border-white/5 p-8 rounded-[32px] shadow-xl">
                      <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">Meta do Mês</p>
                      <div className="flex items-end justify-between mb-3">
                        <span className="text-2xl font-black text-white">{formatCurrency(session?.monthlyGoal || 5000)}</span>
                        <span className="text-xs font-black text-elite-cyan-400">{stats.goalPercent}%</span>
                      </div>
                      <div className="h-2.5 w-full bg-slate-950 rounded-full overflow-hidden">
                        <div className="h-full bg-elite-cyan-500 transition-all duration-1000" style={{ width: `${stats.goalPercent}%` }} />
                      </div>
                   </div>
                   <div className="bg-elite-red-500/10 border border-elite-red-500/20 p-8 rounded-[32px] shadow-xl flex items-center justify-between">
                      <div>
                        <p className="text-[10px] font-black text-elite-red-400 uppercase tracking-widest mb-2">Cortes Hoje</p>
                        <span className="text-4xl font-black text-white">{stats.todayCuts}</span>
                      </div>
                      <div className="h-12 w-12 rounded-2xl bg-elite-red-500 flex items-center justify-center text-white shadow-lg"><Scissors size={24} /></div>
                   </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
                 {[
                   { l: 'Ticket Médio', v: formatCurrency(stats.monthlyRev / (stats.monthlyCuts || 1)), i: <DollarSign size={18}/>, c: 'text-emerald-400' },
                   { l: 'Membros VIP', v: clients.length, i: <Crown size={18}/>, c: 'text-amber-400' },
                   { l: 'Cortes Mensais', v: stats.monthlyCuts, i: <Activity size={18}/>, c: 'text-elite-lilac-400' },
                   { l: 'Caixa Hoje', v: formatCurrency(stats.dailyRev), i: <Wallet size={18}/>, c: 'text-elite-cyan-400' },
                 ].map((s, i) => (
                   <div key={i} className="bg-slate-900/30 border border-white/5 p-8 rounded-[28px] hover:border-white/10 transition-all">
                      <div className={`mb-4 ${s.c}`}>{s.i}</div>
                      <p className="text-[10px] font-black uppercase text-slate-500 tracking-widest mb-1">{s.l}</p>
                      <p className="text-2xl font-black text-white tracking-tight">{s.v}</p>
                   </div>
                 ))}
              </div>
            </div>
          )}

          {activeTab === Tab.Agenda && (
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 animate-in slide-in-from-bottom duration-500">
               <div className="lg:col-span-1">
                  <Card title="Novo Agendamento" icon={<Plus size={16}/>}>
                     <form className="space-y-5" onSubmit={handleAgendaSubmit}>
                        <Input label="DATA" name="d" type="date" defaultValue={selectedDate} required />
                        <Input label="HORÁRIO" name="t" type="time" required />
                        <div className="space-y-2 relative">
                           <label className="text-[10px] font-black text-elite-cyan-400 uppercase tracking-widest ml-1">CLIENTE</label>
                           <input type="text" placeholder="Buscar..." className="w-full bg-slate-950 border border-white/10 rounded-xl px-4 py-3 text-white text-xs font-bold focus:border-elite-red-500 outline-none" value={aptClientSearch} onChange={(e) => { setAptClientSearch(e.target.value); setShowAptResults(true); }} />
                           {showAptResults && aptClientSearchResults.length > 0 && (
                              <div className="absolute z-50 left-0 right-0 mt-2 bg-slate-900 border border-white/10 rounded-xl shadow-2xl overflow-hidden">
                                 {aptClientSearchResults.map(c => (
                                    <button key={c.id} type="button" className="w-full text-left px-4 py-3 hover:bg-white/5 flex flex-col" onClick={() => { setSelectedAptClient(c); setAptClientSearch(c.name); setShowAptResults(false); }}>
                                       <span className="text-[10px] font-black text-white uppercase">{c.name}</span>
                                       <span className="text-[8px] text-slate-500">{c.phone}</span>
                                    </button>
                                 ))}
                              </div>
                           )}
                        </div>
                        <div className="space-y-2">
                           <label className="text-[10px] font-black text-elite-cyan-400 uppercase tracking-widest ml-1">SERVIÇO</label>
                           <select name="s" className="w-full bg-slate-950 border border-white/10 rounded-xl p-3 text-[10px] text-white uppercase font-black focus:border-elite-red-500 outline-none" required>
                             {services.map(s => <option key={s.id} value={s.id}>{s.name} - R$ {s.price}</option>)}
                           </select>
                        </div>
                        <Button type="submit" className="w-full">Agendar Agora</Button>
                     </form>
                  </Card>
               </div>

               <div className="lg:col-span-3 space-y-6">
                  <div className="flex items-center justify-between bg-slate-900/40 p-6 rounded-[24px] border border-white/5">
                     <h3 className="font-black uppercase text-xs tracking-widest text-white flex items-center gap-3">Agenda de Hoje</h3>
                     <input type="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)} className="bg-slate-950 border border-white/10 rounded-lg px-3 py-2 text-[10px] font-black text-white uppercase outline-none focus:border-elite-red-500" />
                  </div>

                  <div className="space-y-4">
                     {filteredAppointments.length > 0 ? filteredAppointments.map(apt => {
                        const c = clients.find(cl => cl.id === apt.clientId);
                        const s = services.find(sv => sv.id === apt.serviceId);
                        return (
                          <div key={apt.id} className="bg-slate-900/60 border border-white/5 p-6 rounded-[28px] flex items-center justify-between group hover:border-elite-red-500/30 transition-all shadow-lg">
                             <div className="flex items-center gap-6">
                                <span className="text-3xl font-black text-white">{apt.time}</span>
                                <div>
                                   <p className="font-black text-lg uppercase text-white leading-none mb-1">{c?.name}</p>
                                   <span className="text-[10px] font-black text-elite-cyan-400 uppercase">{s?.name} • R$ {s?.price}</span>
                                </div>
                             </div>
                             <div className="flex items-center gap-2">
                                <div className="flex flex-col gap-1 items-end mr-4">
                                   <p className="text-[8px] font-black text-slate-500 uppercase mb-1">Concluir Atendimento</p>
                                   <div className="flex gap-2">
                                      <Button variant="success" size="sm" onClick={() => toggleCompleteFlow(apt.id, true)} className="flex items-center gap-2 px-3 h-10">
                                         <CheckCircle2 size={16}/> Pago
                                      </Button>
                                      <Button variant="warning" size="sm" onClick={() => toggleCompleteFlow(apt.id, false)} className="flex items-center gap-2 px-3 h-10">
                                         <Clock size={16}/> Pendente
                                      </Button>
                                   </div>
                                </div>
                                <button onClick={() => setAppointments(prev => prev.filter(x => x.id !== apt.id))} className="p-3 text-slate-700 hover:text-red-500 transition-colors"><Trash2 size={20}/></button>
                             </div>
                          </div>
                        );
                     }) : (
                        <div className="p-20 text-center border-2 border-dashed border-white/5 rounded-[32px]">
                           <Calendar size={40} className="mx-auto mb-4 opacity-10" />
                           <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Agenda vazia para este dia</p>
                        </div>
                     )}
                  </div>
               </div>
            </div>
          )}

          {activeTab === Tab.Finance && (
            <div className="space-y-8 animate-in fade-in duration-500">
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  <div className="bg-emerald-500/5 border border-emerald-500/20 p-8 rounded-[28px]">
                     <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-1">Total Recebido</p>
                     <p className="text-3xl font-black text-white">{formatCurrency(stats.monthlyRev)}</p>
                  </div>
                  <div className="bg-amber-500/5 border border-amber-500/20 p-8 rounded-[28px]">
                     <p className="text-[10px] font-black text-amber-500 uppercase tracking-widest mb-1">Dívidas Clientes</p>
                     <p className="text-3xl font-black text-white">
                        {formatCurrency(appointments.filter(a => a.completed && !a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0))}
                     </p>
                  </div>
                  <div className="bg-elite-red-500/5 border border-elite-red-500/20 p-8 rounded-[28px]">
                     <p className="text-[10px] font-black text-elite-red-500 uppercase tracking-widest mb-1">Saídas Hoje</p>
                     <p className="text-3xl font-black text-white">{formatCurrency(Math.abs(adjustments.filter(a => a.date === new Date().toISOString().split('T')[0] && a.amount < 0).reduce((acc, a) => acc + a.amount, 0)))}</p>
                  </div>
               </div>

               <div className="flex gap-2 bg-slate-900/40 p-1.5 rounded-2xl w-fit">
                  {['pending', 'paid', 'adjustments'].map(t => (
                    <button key={t} onClick={() => setFinanceSubTab(t as any)} className={`px-6 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${financeSubTab === t ? 'bg-elite-red-500 text-white' : 'text-slate-500 hover:text-white'}`}>
                      {t === 'pending' ? 'Pendências' : t === 'paid' ? 'Histórico' : 'Ajustes'}
                    </button>
                  ))}
               </div>

               <Card title={financeSubTab === 'pending' ? "Faturas em Aberto" : financeSubTab === 'paid' ? "Fluxo de Caixa Confirmado" : "Ajustes Manuais"}>
                  <div className="space-y-3">
                     {financeSubTab === 'adjustments' ? adjustments.map(adj => (
                        <div key={adj.id} className="p-6 bg-slate-950/40 border border-white/5 rounded-2xl flex justify-between items-center">
                           <div>
                              <p className={`text-xl font-black ${adj.amount >= 0 ? 'text-emerald-400' : 'text-rose-500'}`}>{adj.amount >= 0 ? '+' : ''}{formatCurrency(adj.amount)}</p>
                              <p className="text-[9px] font-black text-slate-500 uppercase mt-1">{adj.reason} • {adj.date}</p>
                           </div>
                           <button onClick={() => setAdjustments(prev => prev.filter(x => x.id !== adj.id))} className="text-slate-700 hover:text-red-500"><Trash2 size={18}/></button>
                        </div>
                     )) : appointments.filter(a => a.completed && (financeSubTab === 'paid' ? a.paid : !a.paid)).map(apt => (
                        <div key={apt.id} className="p-6 bg-slate-900/40 border border-white/5 rounded-2xl flex justify-between items-center group">
                           <div>
                              <p className="font-black text-white uppercase text-sm">{clients.find(c => c.id === apt.clientId)?.name}</p>
                              <p className="text-[9px] font-black text-slate-500 uppercase mt-1">{apt.date} • {services.find(s => s.id === apt.serviceId)?.name}</p>
                           </div>
                           <div className="flex items-center gap-4">
                              <span className="font-black text-elite-cyan-400">{formatCurrency(services.find(s => s.id === apt.serviceId)?.price || 0)}</span>
                              {financeSubTab === 'pending' && <Button size="sm" variant="success" onClick={() => toggleCompleteFlow(apt.id, true)}>Receber</Button>}
                           </div>
                        </div>
                     ))}
                  </div>
               </Card>
            </div>
          )}

          {activeTab === Tab.Services && (
            <div className="space-y-8 animate-in slide-in-from-right duration-500">
               <Card title={editingServiceId ? "Editar Serviço" : "Novo Serviço"} icon={<Scissors size={18}/>}>
                  <form className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end" onSubmit={(e) => {
                     e.preventDefault();
                     const f = new FormData(e.target as HTMLFormElement);
                     if (editingServiceId) {
                        setServices(prev => prev.map(s => s.id === editingServiceId ? { ...s, name: f.get('n') as string, price: Number(f.get('p')) } : s));
                        setEditingServiceId(null);
                        showToast("Serviço atualizado!");
                     } else {
                        setServices(prev => [...prev, { id: Date.now().toString(), name: f.get('n') as string, price: Number(f.get('p')), duration: 30 }]);
                        showToast("Serviço adicionado!");
                     }
                     (e.target as HTMLFormElement).reset();
                  }}>
                     <Input label="NOME DO SERVIÇO" name="n" placeholder="Ex: Degradê Elite" required />
                     <Input label="PREÇO" name="p" type="number" step="0.01" required />
                     <Button type="submit" className="w-full">{editingServiceId ? 'Salvar Alterações' : 'Adicionar'}</Button>
                  </form>
               </Card>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {services.map(s => (
                    <div key={s.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] hover:border-elite-red-500/30 transition-all group shadow-xl">
                       <div className="flex justify-between items-start mb-6">
                          <h4 className="text-xl font-black text-white uppercase tracking-tight">{s.name}</h4>
                          <div className="flex gap-1">
                             <button onClick={() => { setEditingServiceId(s.id); }} className="p-2 text-slate-700 hover:text-white"><Edit3 size={16}/></button>
                             <button onClick={() => setServices(prev => prev.filter(x => x.id !== s.id))} className="p-2 text-slate-700 hover:text-red-500"><Trash2 size={16}/></button>
                          </div>
                       </div>
                       <p className="text-3xl font-black text-elite-cyan-400">R$ {s.price.toFixed(2)}</p>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {activeTab === Tab.Clients && (
            <div className="space-y-8 animate-in slide-in-from-right duration-500">
               <Card title="Novo Cliente VIP" icon={<Users size={18}/>}>
                  <form className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end" onSubmit={(e) => {
                     e.preventDefault();
                     const f = new FormData(e.target as HTMLFormElement);
                     setClients(prev => [...prev, { id: Date.now().toString(), name: f.get('n') as string, phone: f.get('p') as string, loyaltyPoints: 0, totalSpent: 0 }]);
                     (e.target as HTMLFormElement).reset();
                     showToast("Membro cadastrado!");
                  }}>
                     <Input label="NOME COMPLETO" name="n" placeholder="João Silva" required />
                     <Input label="WHATSAPP" name="p" placeholder="(11) 99999-9999" required />
                     <Button type="submit" className="w-full">Cadastrar Membro</Button>
                  </form>
               </Card>
               <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                  {clients.map(c => (
                    <div key={c.id} className="bg-slate-950/40 border border-white/5 p-8 rounded-[32px] flex items-center justify-between hover:bg-slate-900/40 transition-all shadow-xl">
                       <div className="flex items-center gap-6">
                          <div className="h-16 w-16 rounded-2xl bg-slate-900 border-2 border-elite-red-500/20 flex items-center justify-center text-3xl font-black text-elite-red-500 uppercase">{c.name.charAt(0)}</div>
                          <div><h4 className="text-xl font-black text-white uppercase leading-none">{c.name}</h4><p className="text-elite-cyan-400 text-[10px] font-black uppercase tracking-widest mt-2">{c.phone}</p></div>
                       </div>
                       <button onClick={() => setClients(prev => prev.filter(x => x.id !== c.id))} className="p-4 text-slate-700 hover:text-elite-red-500 transition-colors"><Trash2 size={24}/></button>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {[Tab.Loyalty, Tab.Marketing, Tab.Drinks, Tab.Inventory].includes(activeTab) && (
            <div className="text-center p-20 opacity-30 font-black uppercase text-[10px] tracking-widest animate-pulse border-2 border-dashed border-white/10 rounded-[40px]">
               Módulo {activeTab} em Refinamento...
               <p className="mt-4 text-elite-red-500">Acesse o Painel ou Agenda por enquanto</p>
               <Button onClick={() => setActiveTab(Tab.Dashboard)} className="mt-8">Ir para o Início</Button>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Calendar, Users, Scissors, 
  TrendingUp, Award, Settings, LogOut, 
  Plus, CheckCircle2, DollarSign, Clock, Sparkles,
  Trash2, BellRing, Camera, User as UserIcon,
  Check, Undo2, AlertTriangle, Wallet, Receipt,
  MessageSquare, KeyRound, Smartphone, ShieldCheck,
  Edit3, Save, X, Send, Gift, Target, Zap, Box, Minus,
  Search, Phone, Image as ImageIcon, Briefcase,
  ExternalLink, Crown, Star, Eye, EyeOff, ShoppingCart, Link as LinkIcon,
  Megaphone, Wand2, MessageCircle, ChevronUp, ChevronDown, Activity
} from 'lucide-react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, 
  Tooltip, ResponsiveContainer 
} from 'recharts';

import { Button, Input, Card, Badge } from './components/UI';
import { StorageService } from './services/storage';
import { GeminiService } from './services/gemini';
import { Client, Service, Appointment, UserSession, Tab, Material, Drink, Sale } from './types';

interface BalanceAdjustment {
  id: string;
  amount: number;
  reason: string;
  date: string;
}

const DEFAULT_SERVICES: Service[] = [
  { id: '1', name: 'Corte Social', price: 35, duration: 30 },
  { id: '2', name: 'Degradê Especial', price: 45, duration: 45 },
  { id: '3', name: 'Barba Terápia', price: 25, duration: 25 },
];

const DEFAULT_PROFILE_IMG = "https://images.unsplash.com/photo-1621605815971-fbc98d665033?q=80&w=400&h=400&auto=format&fit=crop";

const LogoElite = ({ className = "h-12 w-12" }: { className?: string }) => (
  <div className={`relative flex items-center justify-center ${className}`}>
    <div className="absolute inset-0 flex items-center justify-center">
      <Scissors className="text-elite-red-500 animate-scissors-left -translate-x-1" size={32} />
      <Scissors className="text-elite-red-500 animate-scissors-right translate-x-1" size={32} />
    </div>
  </div>
);

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(() => StorageService.get<UserSession>('session'));
  const [isAuthenticated, setIsAuthenticated] = useState(!!session);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const getInitialData = <T,>(key: string, defaultValue: T): T => {
    if (!session) return defaultValue;
    return StorageService.get<T>(`${session.username}_${key}`) || defaultValue;
  };

  const [activeTab, setActiveTab] = useState<Tab>(Tab.Dashboard);
  const [financeSubTab, setFinanceSubTab] = useState<'paid' | 'pending' | 'adjustments'>('pending');

  const [clients, setClients] = useState<Client[]>(() => getInitialData('clients', []));
  const [services, setServices] = useState<Service[]>(() => getInitialData('services', DEFAULT_SERVICES));
  const [appointments, setAppointments] = useState<Appointment[]>(() => getInitialData('appointments', []));
  const [adjustments, setAdjustments] = useState<BalanceAdjustment[]>(() => getInitialData('adjustments', []));
  const [sales, setSales] = useState<Sale[]>(() => getInitialData('sales', []));
  const [marketingMsg, setMarketingMsg] = useState(() => getInitialData('marketing_msg', ""));
  const [campaignGoal, setCampaignGoal] = useState(() => getInitialData('campaign_goal', ""));

  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [aptClientSearch, setAptClientSearch] = useState("");
  const [selectedAptClient, setSelectedAptClient] = useState<Client | null>(null);
  const [showAptResults, setShowAptResults] = useState(false);
  const [finishingAptId, setFinishingAptId] = useState<string | null>(null);

  const [isPrivacyMode, setIsPrivacyMode] = useState(false);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
    if (session && isAuthenticated) {
      setIsSaving(true);
      const data: Record<string, any> = { clients, services, appointments, adjustments, sales, marketing_msg: marketingMsg, campaign_goal: campaignGoal };
      Object.entries(data).forEach(([k, v]) => StorageService.set(`${session.username}_${k}`, v));
      const timer = setTimeout(() => setIsSaving(false), 500);
      return () => clearTimeout(timer);
    }
  }, [clients, services, appointments, adjustments, sales, marketingMsg, campaignGoal, session, isAuthenticated]);

  const stats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const monthPrefix = today.substring(0, 7);
    const compApts = appointments.filter(a => a.completed);

    const serviceMonthlyRev = compApts.filter(a => a.date.startsWith(monthPrefix) && a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0);
    const salesMonthlyRev = sales.filter(s => s.date.startsWith(monthPrefix)).reduce((acc, s) => acc + s.price, 0);
    const adjustmentsMonthly = adjustments.filter(a => a.date.startsWith(monthPrefix)).reduce((acc, a) => acc + a.amount, 0);

    const monthlyRev = serviceMonthlyRev + salesMonthlyRev + adjustmentsMonthly;
    const dailyRev = compApts.filter(a => a.date === today && a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0) + 
                     sales.filter(s => s.date === today).reduce((acc, s) => acc + s.price, 0);

    const chartData = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const ds = d.toISOString().split('T')[0];
      const rev = compApts.filter(a => a.date === ds && a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0) +
                  sales.filter(s => s.date === ds).reduce((acc, s) => acc + s.price, 0);
      return { name: d.toLocaleDateString('pt-BR', { weekday: 'short' }), receita: Math.max(0, rev) };
    });

    return { 
      dailyRev, monthlyRev, 
      todayCuts: appointments.filter(a => a.date === today).length, 
      monthlyCuts: compApts.filter(a => a.date.startsWith(monthPrefix)).length,
      goalPercent: Math.min(Math.round((monthlyRev / (session?.monthlyGoal || 5000)) * 100), 100),
      chartData
    };
  }, [appointments, services, sales, adjustments, session?.monthlyGoal]);

  const aptClientSearchResults = useMemo(() => {
    if (!aptClientSearch.trim()) return [];
    return clients.filter(c => c.name.toLowerCase().includes(aptClientSearch.toLowerCase())).slice(0, 5);
  }, [aptClientSearch, clients]);

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    const user = (f.get('username') as string)?.toLowerCase().trim();
    const pass = f.get('password') as string;

    if (authMode === 'register') {
      StorageService.set(`user_auth_${user}`, { username: user, password: pass, shopName: f.get('shopName'), phone: f.get('phone'), profileImage: DEFAULT_PROFILE_IMG, monthlyGoal: 5000 });
      setAuthMode('login');
      showToast("Barbearia cadastrada!");
      return;
    }

    const stored = StorageService.get<any>(`user_auth_${user}`);
    if (!stored || stored.password !== pass) return setAuthError("Credenciais inválidas.");

    const sess: UserSession = { shopName: stored.shopName, username: stored.username, phone: stored.phone, profileImage: stored.profileImage || DEFAULT_PROFILE_IMG, monthlyGoal: stored.monthlyGoal || 5000 };
    StorageService.set('session', sess);
    setSession(sess);
    setIsAuthenticated(true);
  };

  const handleAgendaSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    if (!selectedAptClient) return showToast("Escolha um cliente!", "error");

    setAppointments(prev => [...prev, {
      id: Date.now().toString(),
      clientId: selectedAptClient.id,
      serviceId: f.get('s') as string,
      date: f.get('d') as string,
      time: f.get('t') as string,
      completed: false,
      paid: false
    }]);
    setAptClientSearch("");
    setSelectedAptClient(null);
    showToast("Horário reservado!");
  };

  const toggleCompleteFlow = (id: string, paidStatus: boolean) => {
    setAppointments(prev => prev.map(apt => {
      if (apt.id === id) {
        const s = services.find(sv => sv.id === apt.serviceId);
        if (paidStatus) {
           setClients(prevC => prevC.map(c => c.id === apt.clientId ? { ...c, loyaltyPoints: c.loyaltyPoints + 1, totalSpent: c.totalSpent + (s?.price || 0) } : c));
        }
        return { ...apt, completed: true, paid: paidStatus };
      }
      return apt;
    }));
    setFinishingAptId(null);
    showToast(paidStatus ? "Atendimento Pago com sucesso!" : "Atendimento Finalizado como Pendente!");
  };

  const formatCurrency = (v: number) => isPrivacyMode ? '••••' : `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  if (!isAuthenticated) return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-slate-950">
      <div className="w-full max-w-md space-y-8 animate-in fade-in zoom-in duration-500">
        <div className="text-center">
          <LogoElite className="mx-auto h-24 w-24 mb-4" />
          <h2 className="text-4xl font-black text-white uppercase tracking-tighter italic">Elite <span className="text-elite-red-500">Barber</span></h2>
          <p className="text-[10px] font-black text-elite-cyan-400 uppercase tracking-[0.3em] mt-2">Management Suite v2.0</p>
        </div>
        <Card className="glass-card">
          <form className="space-y-4" onSubmit={handleAuth}>
            {authError && <p className="text-[10px] text-red-500 font-black uppercase text-center bg-red-500/10 p-2 rounded-lg">{authError}</p>}
            {authMode === 'register' && (
              <>
                <Input label="NOME DA BARBEARIA" name="shopName" placeholder="EX: BARBER SHOP" required />
                <Input label="WHATSAPP" name="phone" placeholder="(11) 99999-9999" required />
              </>
            )}
            <Input label="USUÁRIO" name="username" placeholder="admin" required />
            <Input label="SENHA" name="password" type="password" placeholder="••••••••" required />
            <Button type="submit" className="w-full py-4">{authMode === 'login' ? 'ENTRAR NO SISTEMA' : 'CRIAR MINHA UNIDADE'}</Button>
            <button type="button" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')} className="w-full text-[10px] text-slate-500 font-black uppercase tracking-widest hover:text-elite-red-500 transition-colors">
              {authMode === 'login' ? 'REGISTRAR NOVA BARBEARIA' : 'JÁ POSSUO CADASTRO'}
            </button>
          </form>
        </Card>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen text-slate-100 flex overflow-hidden bg-slate-950">
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-950/80 backdrop-blur-2xl border-r border-white/5 transition-all duration-300 lg:relative ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:w-20 lg:translate-x-0'}`}>
        <div className="h-full flex flex-col p-6">
          <div className="mb-10 flex items-center gap-4 overflow-hidden">
            <LogoElite className="h-10 w-10 min-w-[40px]" />
            {isSidebarOpen && <div className="truncate"><h1 className="text-[10px] font-black text-white uppercase tracking-widest">Elite Barber</h1><p className="text-[8px] text-elite-red-500 font-black uppercase truncate">{session?.shopName}</p></div>}
          </div>
          <nav className="flex-1 space-y-1.5">
            {[
