                             <h4 className="text-xl font-black text-white uppercase tracking-tight">{c.name}</h4>
                             <div className="flex items-center gap-3 mt-3">
                                <Badge variant="lilac">{c.loyaltyPoints} PONTOS</Badge>
                                <span className="text-emerald-400 text-[10px] font-black uppercase tracking-widest">{formatCurrency(c.totalSpent)} GASTO</span>
                             </div>
                          </div>
                       </div>
                       <div className="flex gap-2">
                          <button onClick={() => window.open(`https://wa.me/55${c.phone.replace(/\D/g,'')}`, '_blank')} className="p-4 bg-emerald-500/10 text-emerald-500 rounded-2xl hover:bg-emerald-500 transition-all"><MessageCircle size={24}/></button>
                          <button onClick={() => setClients(prev => prev.filter(x => x.id !== c.id))} className="p-4 text-slate-700 hover:text-red-500"><Trash2 size={24}/></button>
                       </div>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {activeTab === Tab.Services && (
            <div className="space-y-8 animate-in slide-in-from-right duration-500">
               <Card title="Serviços" icon={<Scissors size={18}/>}>
                  <form className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end" onSubmit={(e) => {
                     e.preventDefault();
                     const f = new FormData(e.target as HTMLFormElement);
                     setServices(prev => [...prev, { id: Date.now().toString(), name: f.get('n') as string, price: Number(f.get('p')), duration: 30 }]);
                     (e.target as HTMLFormElement).reset();
                     showToast("Serviço adicionado!");
                  }}>
                     <Input label="NOME" name="n" required />
                     <Input label="PREÇO" name="p" type="number" step="0.01" required />
                     <Button type="submit" className="w-full">ADICIONAR</Button>
                  </form>
               </Card>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {services.map(s => (
                    <div key={s.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[40px] hover:border-elite-red-500/30 transition-all shadow-xl group">
                       <h4 className="text-lg font-black text-white uppercase mb-2">{s.name}</h4>
                       <p className="text-3xl font-black text-elite-cyan-400">{formatCurrency(s.price)}</p>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {activeTab === Tab.Profile && (
            <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in duration-500">
               <Card title="Perfil" icon={<Settings size={16}/>}>
                  <div className="space-y-6">
                     <div className="flex justify-center mb-8">
                        <div className="relative group">
                           <div className="h-32 w-32 rounded-[40px] border-4 border-elite-red-500 overflow-hidden shadow-2xl">
                              <img src={session?.profileImage} className="h-full w-full object-cover" />
                           </div>
                        </div>
                     </div>
                     <Input label="BARBEARIA" value={session?.shopName} readOnly />
                     <Input label="META MENSAL (R$)" type="number" value={session?.monthlyGoal} onChange={e => setSession(s => s ? {...s, monthlyGoal: Number(e.target.value)} : null)} />
                     <Button className="w-full py-4" onClick={() => {
                        StorageService.set(`user_auth_${session?.username}`, {...StorageService.get(`user_auth_${session?.username}`), ...session});
                        showToast("Salvo!");
                     }}>ATUALIZAR CONFIGURAÇÕES</Button>
                  </div>
               </Card>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Calendar, Users, Scissors, 
  TrendingUp, Award, Settings, LogOut, 
  Plus, CheckCircle2, DollarSign, Clock, Sparkles,
  Trash2, BellRing, Camera, User as UserIcon,
  Check, Undo2, AlertTriangle, Wallet, Receipt,
  MessageSquare, KeyRound, Smartphone, ShieldCheck,
  Edit3, Save, X, Send, Gift, Target, Zap, Box, Minus,
  Search, Phone, Image as ImageIcon, Briefcase,
  ExternalLink, Crown, Star, Eye, EyeOff, ShoppingCart, Link as LinkIcon,
  Megaphone, Wand2, MessageCircle, ChevronUp, ChevronDown, Activity, Beer, ArrowUpCircle, ArrowDownCircle,
  FileBarChart, History, PieChart, BarChart3, Filter
} from 'lucide-react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, 
  Tooltip, ResponsiveContainer, BarChart, Bar
} from 'recharts';

import { Button, Input, Card, Badge } from './components/UI';
import { StorageService } from './services/storage';
import { GeminiService } from './services/gemini';
import { Client, Service, Appointment, UserSession, Tab, Material, Drink, Sale } from './types';

interface BalanceAdjustment {
  id: string;
  amount: number;
  reason: string;
  date: string;
}

const DEFAULT_SERVICES: Service[] = [
  { id: '1', name: 'Corte Social', price: 35, duration: 30 },
  { id: '2', name: 'Degradê Especial', price: 45, duration: 45 },
  { id: '3', name: 'Barba Terápia', price: 25, duration: 25 },
];

const DEFAULT_PROFILE_IMG = "https://images.unsplash.com/photo-1621605815971-fbc98d665033?q=80&w=400&h=400&auto=format&fit=crop";

const LogoElite = ({ className = "h-12 w-12" }: { className?: string }) => (
  <div className={`relative flex items-center justify-center ${className}`}>
    <div className="absolute inset-0 flex items-center justify-center">
      <Scissors className="text-elite-red-500 animate-scissors-left -translate-x-1" size={32} />
      <Scissors className="text-elite-red-500 animate-scissors-right translate-x-1" size={32} />
    </div>
  </div>
);

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(() => StorageService.get<UserSession>('session'));
  const [isAuthenticated, setIsAuthenticated] = useState(!!session);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const getInitialData = <T,>(key: string, defaultValue: T): T => {
    if (!session) return defaultValue;
    return StorageService.get<T>(`${session.username}_${key}`) || defaultValue;
  };

  const [activeTab, setActiveTab] = useState<Tab>(Tab.Dashboard);
  const [financeSubTab, setFinanceSubTab] = useState<'paid' | 'pending' | 'adjustments'>('pending');

  const [clients, setClients] = useState<Client[]>(() => getInitialData('clients', []));
  const [services, setServices] = useState<Service[]>(() => getInitialData('services', DEFAULT_SERVICES));
  const [materials, setMaterials] = useState<Material[]>(() => getInitialData('materials', []));
  const [drinks, setDrinks] = useState<Drink[]>(() => getInitialData('drinks', []));
  const [sales, setSales] = useState<Sale[]>(() => getInitialData('sales', []));
  const [appointments, setAppointments] = useState<Appointment[]>(() => getInitialData('appointments', []));
  const [adjustments, setAdjustments] = useState<BalanceAdjustment[]>(() => getInitialData('adjustments', []));
  const [marketingMsg, setMarketingMsg] = useState(() => getInitialData('marketing_msg', ""));
  const [campaignGoal, setCampaignGoal] = useState(() => getInitialData('campaign_goal', ""));

  const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
  const [reportMonth, setReportMonth] = useState(new Date().toISOString().substring(0, 7)); // YYYY-MM
  const [aptClientSearch, setAptClientSearch] = useState("");
  const [selectedAptClient, setSelectedAptClient] = useState<Client | null>(null);
  const [showAptResults, setShowAptResults] = useState(false);
  const [finishingAptId, setFinishingAptId] = useState<string | null>(null);
  const [isGeneratingMessage, setIsGeneratingMessage] = useState(false);
  const [isSendingReminder, setIsSendingReminder] = useState<string | null>(null);

  const [isPrivacyMode, setIsPrivacyMode] = useState(false);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
    if (session && isAuthenticated) {
      setIsSaving(true);
      const data: Record<string, any> = { clients, services, materials, drinks, appointments, adjustments, sales, marketing_msg: marketingMsg, campaign_goal: campaignGoal };
      Object.entries(data).forEach(([k, v]) => StorageService.set(`${session.username}_${k}`, v));
      const timer = setTimeout(() => setIsSaving(false), 500);
      return () => clearTimeout(timer);
    }
  }, [clients, services, materials, drinks, appointments, adjustments, sales, marketingMsg, campaignGoal, session, isAuthenticated]);

  const stats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const monthPrefix = today.substring(0, 7);
    const yearPrefix = today.substring(0, 4);
    const selectedMonthPrefix = reportMonth;

    const compApts = appointments.filter(a => a.completed);

    // Stats para Dash Geral (Mês Atual)
    const serviceMonthlyRev = compApts.filter(a => a.date.startsWith(monthPrefix) && a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0);
    const salesMonthlyRev = sales.filter(s => s.date.startsWith(monthPrefix)).reduce((acc, s) => acc + s.price, 0);
    const adjustmentsMonthly = adjustments.filter(a => a.date.startsWith(monthPrefix)).reduce((acc, a) => acc + a.amount, 0);
    const monthlyRevTotal = serviceMonthlyRev + salesMonthlyRev + adjustmentsMonthly;

    // Stats para Aba Relatórios (Mês Selecionado)
    const reportApts = compApts.filter(a => a.date.startsWith(selectedMonthPrefix));
    const reportSales = sales.filter(s => s.date.startsWith(selectedMonthPrefix));
    const reportAdjusts = adjustments.filter(a => a.date.startsWith(selectedMonthPrefix));

    const reportCutsCount = reportApts.length;
    const reportServiceRev = reportApts.filter(a => a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0);
    const reportProductRev = reportSales.reduce((acc, s) => acc + s.price, 0);
    const reportAdjustRev = reportAdjusts.reduce((acc, a) => acc + a.amount, 0);
    const reportTotalRev = reportServiceRev + reportProductRev + reportAdjustRev;

    // Outras métricas
    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
    const cutsThisWeek = compApts.filter(a => new Date(a.date) >= sevenDaysAgo).length;
    const cutsThisYear = compApts.filter(a => a.date.startsWith(yearPrefix)).length;

    const chartData = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const ds = d.toISOString().split('T')[0];
      const rev = compApts.filter(a => a.date === ds && a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0) +
                  sales.filter(s => s.date === ds).reduce((acc, s) => acc + s.price, 0) +
                  adjustments.filter(a => a.date === ds).reduce((acc, a) => acc + a.amount, 0);
      return { name: d.toLocaleDateString('pt-BR', { weekday: 'short' }), receita: Math.max(0, rev) };
    });

    const monthlyReportData = Array.from({ length: 12 }, (_, i) => {
      const monthStr = `${yearPrefix}-${(i + 1).toString().padStart(2, '0')}`;
      const count = compApts.filter(a => a.date.startsWith(monthStr)).length;
      return {
        month: new Date(yearPrefix + '-' + (i + 1)).toLocaleString('pt-BR', { month: 'short' }).toUpperCase(),
        count: count
      };
    });

    return { 
      dailyRev: compApts.filter(a => a.date === today && a.paid).reduce((acc, a) => acc + (services.find(s => s.id === a.serviceId)?.price || 0), 0) + sales.filter(s => s.date === today).reduce((acc, s) => acc + s.price, 0) + adjustments.filter(a => a.date === today).reduce((acc, a) => acc + a.amount, 0),
      monthlyRev: monthlyRevTotal, 
      todayCuts: compApts.filter(a => a.date === today).length,
      weekCuts: cutsThisWeek,
      monthlyCuts: compApts.filter(a => a.date.startsWith(monthPrefix)).length,
      yearlyCuts: cutsThisYear,
      reportCuts: reportCutsCount,
      reportRevenue: reportTotalRev,
      goalPercent: Math.min(Math.round((monthlyRevTotal / (session?.monthlyGoal || 5000)) * 100), 100),
      chartData,
      monthlyReportData
    };
  }, [appointments, services, sales, adjustments, session?.monthlyGoal, reportMonth]);

  const toggleCompleteFlow = (id: string, paidStatus: boolean) => {
    setAppointments(prev => prev.map(apt => {
      if (apt.id === id) {
        const s = services.find(sv => sv.id === apt.serviceId);
        if (paidStatus) {
           setClients(prevC => prevC.map(c => c.id === apt.clientId ? { ...c, loyaltyPoints: c.loyaltyPoints + 1, totalSpent: c.totalSpent + (s?.price || 0) } : c));
        }
        return { ...apt, completed: true, paid: paidStatus };
      }
      return apt;
    }));
    setFinishingAptId(null);
    showToast(paidStatus ? "Atendimento Pago!" : "Finalizado como Pendente!");
  };

  const sendReminder = async (aptId: string) => {
    const apt = appointments.find(a => a.id === aptId);
    if (!apt) return;
    const client = clients.find(c => c.id === apt.clientId);
    const service = services.find(s => s.id === apt.serviceId);
    if (!client || !service) return;
    setIsSendingReminder(aptId);
    try {
      const msg = await GeminiService.generateBusinessMessage('reminder', client.name, service.name, apt.time);
      window.open(`https://wa.me/55${client.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
      showToast("Lembrete gerado com IA!");
    } catch (error) { showToast("Erro ao gerar lembrete", "error"); }
    finally { setIsSendingReminder(null); }
  };

  const sellDrink = (drink: Drink) => {
    if (drink.stock <= 0) return showToast("Sem estoque!", "error");
    setSales(prev => [...prev, { id: Date.now().toString(), itemId: drink.id, itemName: drink.name, price: drink.price, date: new Date().toISOString().split('T')[0] }]);
    setDrinks(prev => prev.map(d => d.id === drink.id ? { ...d, stock: d.stock - 1 } : d));
    showToast(`${drink.name} vendida!`);
  };

  const formatCurrency = (v: number) => isPrivacyMode ? '••••' : `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    const user = (f.get('username') as string)?.toLowerCase().trim();
    const pass = f.get('password') as string;
    if (authMode === 'register') {
      StorageService.set(`user_auth_${user}`, { username: user, password: pass, shopName: f.get('shopName'), phone: f.get('phone'), profileImage: DEFAULT_PROFILE_IMG, monthlyGoal: 5000 });
      setAuthMode('login');
      showToast("Barbearia cadastrada!");
      return;
    }
    const stored = StorageService.get<any>(`user_auth_${user}`);
    if (!stored || stored.password !== pass) return setAuthError("Credenciais inválidas.");
    const sess: UserSession = { shopName: stored.shopName, username: stored.username, phone: stored.phone, profileImage: stored.profileImage || DEFAULT_PROFILE_IMG, monthlyGoal: stored.monthlyGoal || 5000 };
    StorageService.set('session', sess);
    setSession(sess);
    setIsAuthenticated(true);
  };

  if (!isAuthenticated) return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-slate-950">
      <div className="w-full max-w-md space-y-8 animate-in fade-in zoom-in duration-500">
        <div className="text-center">
          <LogoElite className="mx-auto h-24 w-24 mb-4" />
          <h2 className="text-3xl font-black text-white uppercase tracking-tighter italic leading-none">Barbershop<br/><span className="text-elite-red-500 text-4xl">Matheus Farias</span></h2>
        </div>
        <Card className="glass-card">
          <form className="space-y-4" onSubmit={handleAuth}>
            {authError && <p className="text-[10px] text-red-500 font-black uppercase text-center bg-red-500/10 p-2 rounded-lg">{authError}</p>}
            {authMode === 'register' && (
              <>
                <Input label="NOME DA BARBEARIA" name="shopName" placeholder="EX: BARBER SHOP" required />
                <Input label="WHATSAPP" name="phone" placeholder="(11) 99999-9999" required />
              </>
            )}
            <Input label="USUÁRIO" name="username" placeholder="admin" required />
            <Input label="SENHA" name="password" type="password" placeholder="••••••••" required />
            <Button type="submit" className="w-full py-4">{authMode === 'login' ? 'ENTRAR' : 'CADASTRAR'}</Button>
            <button type="button" onClick={() => setAuthMode(authMode === 'login' ? 'register' : 'login')} className="w-full text-[10px] text-slate-500 font-black uppercase tracking-widest hover:text-elite-red-500 transition-colors">
              {authMode === 'login' ? 'CRIAR CONTA' : 'VOLTAR'}
            </button>
          </form>
        </Card>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen text-slate-100 flex overflow-hidden bg-slate-950">
      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-950/80 backdrop-blur-2xl border-r border-white/5 transition-all duration-300 lg:relative ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:w-20 lg:translate-x-0'}`}>
        <div className="h-full flex flex-col p-6">
          <div className="mb-8 flex items-center gap-4 overflow-hidden">
            <LogoElite className="h-10 w-10 min-w-[40px]" />
            {isSidebarOpen && <div className="truncate"><h1 className="text-[10px] font-black text-white uppercase tracking-widest">Matheus Farias</h1><p className="text-[8px] text-elite-red-500 font-black uppercase truncate">{session?.shopName}</p></div>}
          </div>
          <nav className="flex-1 space-y-1 overflow-y-auto pr-2 custom-scrollbar">
            {[
              { id: Tab.Dashboard, icon: LayoutDashboard, label: 'Painel' },
              { id: Tab.Agenda, icon: Calendar, label: 'Agenda' },
              { id: Tab.Clients, icon: Users, label: 'Clientes' },
              { id: Tab.Finance, icon: TrendingUp, label: 'Financeiro' },
              { id: Tab.Reports, icon: FileBarChart, label: 'Relatórios' },
              { id: Tab.Loyalty, icon: Award, label: 'Fidelidade' },
              { id: Tab.Marketing, icon: Megaphone, label: 'Marketing AI' },
              { id: Tab.Services, icon: Scissors, label: 'Serviços' },
              { id: Tab.Drinks, icon: Beer, label: 'Bar' },
              { id: Tab.Inventory, icon: Box, label: 'Estoque' },
              { id: Tab.Profile, icon: Settings, label: 'Configurações' },
            ].map(item => (
              <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === item.id ? 'bg-elite-red-500 text-white shadow-lg' : 'text-slate-500 hover:text-elite-red-500 hover:bg-white/5'}`}>
                <item.icon size={16} />
                {isSidebarOpen && <span>{item.label}</span>}
              </button>
            ))}
          </nav>
          <button onClick={() => { StorageService.remove('session'); window.location.reload(); }} className="mt-6 flex items-center gap-3 px-4 py-3 text-[10px] font-black uppercase text-red-500 hover:bg-red-500/10 rounded-xl transition-colors">
            <LogOut size={16} />
            {isSidebarOpen && <span>Sair</span>}
          </button>
        </div>
      </aside>

      <main className="flex-1 h-screen overflow-y-auto">
        <header className="sticky top-0 z-40 bg-slate-950/60 backdrop-blur-xl border-b border-white/5 px-8 py-4 flex items-center justify-between">
           <div className="flex items-center gap-4">
              <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-500 hover:text-white lg:hidden"><LayoutDashboard size={18}/></button>
              <h2 className="text-sm font-black uppercase tracking-widest text-white">{activeTab}</h2>
           </div>
           <div className="flex items-center gap-4">
              {isSaving && <Badge variant="cyan" className="animate-pulse">SINCRONIZANDO</Badge>}
              <button onClick={() => setIsPrivacyMode(!isPrivacyMode)} className="p-2 bg-slate-900 border border-white/5 rounded-lg text-slate-400 hover:text-elite-cyan-400">
                {isPrivacyMode ? <EyeOff size={16}/> : <Eye size={16}/>}
              </button>
              <div className="h-8 w-8 rounded-lg border border-elite-red-500/30 bg-slate-900 flex items-center justify-center overflow-hidden">
                 <img src={session?.profileImage} className="h-full w-full object-cover" />
              </div>
           </div>
        </header>

        <div className="p-8 max-w-7xl mx-auto space-y-8 pb-32">
          {toast && (
            <div className={`fixed bottom-10 right-10 z-[100] px-6 py-4 rounded-2xl text-[10px] font-black uppercase flex items-center gap-3 animate-in slide-in-from-right duration-300 shadow-2xl ${toast.type === 'error' ? 'bg-red-600 text-white' : 'bg-elite-cyan-500 text-black'}`}>
              {toast.type === 'error' ? <AlertTriangle size={16}/> : <CheckCircle2 size={16}/>} {toast.message}
            </div>
          )}

          {activeTab === Tab.Reports && (
            <div className="space-y-8 animate-in fade-in duration-500">
               {/* Seletor de Mês */}
               <div className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex items-center justify-between gap-6 flex-wrap">
                  <div className="flex items-center gap-3">
                     <div className="p-3 bg-elite-red-500/10 text-elite-red-500 rounded-xl"><Filter size={20}/></div>
                     <div>
                        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Filtro de Análise</h4>
                        <p className="text-xs font-bold text-white uppercase">Verificar Mês Específico</p>
                     </div>
                  </div>
                  <input 
                    type="month" 
                    value={reportMonth} 
                    onChange={(e) => setReportMonth(e.target.value)}
                    className="bg-slate-950 border border-white/10 rounded-xl px-6 py-3 text-white text-xs font-black uppercase outline-none focus:border-elite-red-500 transition-colors"
                  />
               </div>

               {/* Cards de Resumo do Mês Selecionado */}
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                  <div className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] hover:border-elite-red-500/30 transition-all shadow-xl">
                     <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 flex items-center gap-2"><Scissors size={14}/> Cortes no Mês</p>
                     <h3 className="text-4xl font-black text-white">{stats.reportCuts}</h3>
                  </div>
                  <div className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] hover:border-emerald-500/30 transition-all shadow-xl">
                     <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 flex items-center gap-2"><DollarSign size={14}/> Receita Mês</p>
                     <h3 className="text-4xl font-black text-white">{formatCurrency(stats.reportRevenue)}</h3>
                  </div>
                  <div className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] hover:border-elite-cyan-500/30 transition-all shadow-xl">
                     <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1 flex items-center gap-2"><Calendar size={14}/> Total Ano</p>
