                              <button onClick={() => setAdjustments(prev => prev.filter(x => x.id !== adj.id))} className="p-2 text-slate-700 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 size={16}/></button>
                           </div>
