              {authMode === 'login' && (
                <button type="button" onClick={() => { setAuthMode('reset'); setAuthError(null); }} className="w-full text-[10px] text-slate-700 font-black uppercase tracking-widest hover:text-elite-cyan-500 transition-colors">
