                        <h4 className="font-black uppercase text-[10px] text-elite-cyan-400 mb-6 flex items-center gap-2 tracking-widest"><Users size={14}/> Enviar para Lista VIP</h4>
                        <div className="max-h-[300px] overflow-y-auto space-y-2 pr-2 custom-scrollbar">
                           {clients.map(c => (
                              <div key={c.id} className="flex items-center justify-between p-4 bg-slate-950/40 rounded-xl border border-white/5 group hover:border-emerald-500/30 transition-all">
