                        const amount = Number(f.get('a'));
                        setAdjustments(prev => [...prev, { id: Date.now().toString(), amount: isAdd ? amount : -amount, reason: f.get('r') as string, date: new Date().toISOString().split('T')[0] }]);
                        (e.target as HTMLFormElement).reset();
                        showToast(isAdd ? "Entrada registrada!" : "Retirada registrada!");
                      }}>
                         <Input name="a" type="number" step="0.01" placeholder="R$ 0,00" required />
                         <Input name="r" placeholder="Motivo" required />
                         <div className="grid grid-cols-2 gap-2">
                            <Button name="add" type="submit" variant="success" size="sm">ENTRADA</Button>
                            <Button name="remove" type="submit" variant="danger" size="sm">SAÍDA</Button>
                         </div>
                      </form>
                   </Card>
                </div>
              </div>
            </div>
