                     <div key={d.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] shadow-xl group hover:border-elite-red-500/30 transition-all">
                        <div className="flex justify-between items-start mb-6">
                           <h4 className="text-lg font-black text-white uppercase leading-tight">{d.name}</h4>
