                        <Button variant="success" className="w-full" onClick={() => sellDrink(d)} disabled={d.stock <= 0}><ShoppingCart size={18} className="mr-2"/> VENDER</Button>
                     </div>
                  ))}
               </div>
            </div>
          )}

