                  <form className="grid grid-cols-1 md:grid-cols-4 gap-6 items-end" onSubmit={(e) => {
                     e.preventDefault();
                     const f = new FormData(e.target as HTMLFormElement);
                     setMaterials(prev => [...prev, { id: Date.now().toString(), name: f.get('n') as string, quantity: Number(f.get('q')), minQuantity: Number(f.get('mq')), unit: 'un' }]);
                     (e.target as HTMLFormElement).reset();
                     showToast("Insumo cadastrado!");
                  }}>
                     <Input label="MATERIAL" name="n" placeholder="Lâminas/Golas/Capa" required />
                     <Input label="QTD ATUAL" name="q" type="number" required />
                     <Input label="ESTOQUE MÍNIMO" name="mq" type="number" required />
                     <Button type="submit" className="w-full">SALVAR</Button>
                  </form>
               </Card>
