                           <h4 className="text-lg font-black text-white uppercase">{m.name}</h4>
                           <div className="flex gap-2">
                              <button onClick={() => setMaterials(prev => prev.map(x => x.id === m.id ? {...x, quantity: x.quantity + 1} : x))} className="p-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-all"><Plus size={14}/></button>
