                           </div>
                        </div>
                        <div className="flex items-center justify-between">
                           <span className={`text-4xl font-black ${m.quantity <= m.minQuantity ? 'text-red-500' : 'text-elite-cyan-400'}`}>{m.quantity}</span>
                           <div className="text-right">
                              <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1">Mínimo</p>
                              <span className="text-sm font-black text-white">{m.minQuantity} un</span>
                           </div>
                        </div>
                     </div>
                  ))}
               </div>
            </div>
