                        <Input label="META DE FATURAMENTO MENSAL (R$)" type="number" value={session?.monthlyGoal} onChange={e => setSession(s => s ? {...s, monthlyGoal: Number(e.target.value)} : null)} />
                     </div>
                     <div className="bg-elite-cyan-500/5 border border-elite-cyan-500/10 p-6 rounded-2xl">
                        <p className="text-[10px] font-black text-elite-cyan-400 uppercase tracking-widest text-center">As informações acima são salvas automaticamente.</p>
                     </div>
                  </div>
               </Card>
            </div>
          )}

          {activeTab === Tab.Finance && (
            <div className="space-y-8 animate-in fade-in duration-500">
