const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(() => StorageService.get<UserSession>('session'));
  const [isAuthenticated, setIsAuthenticated] = useState(!!session);
  const [authMode, setAuthMode] = useState<'login' | 'register' | 'reset'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const getInitialData = <T,>(key: string, defaultValue: T): T => {
    if (!session) return defaultValue;
    return StorageService.get<T>(`${session.username}_${key}`) || defaultValue;
  };

  const [activeTab, setActiveTab] = useState<Tab>(() => getInitialData('active_tab', Tab.Dashboard));
  const [financeSubTab, setFinanceSubTab] = useState<'paid' | 'pending' | 'adjustments'>('pending');

  const [clients, setClients] = useState<Client[]>(() => getInitialData('clients', []));
  const [services, setServices] = useState<Service[]>(() => getInitialData('services', DEFAULT_SERVICES));
  const [materials, setMaterials] = useState<Material[]>(() => getInitialData('materials', []));
  const [drinks, setDrinks] = useState<Drink[]>(() => getInitialData('drinks', []));
  const [sales, setSales] = useState<Sale[]>(() => getInitialData('sales', []));
  const [appointments, setAppointments] = useState<Appointment[]>(() => getInitialData('appointments', []));
  const [adjustments, setAdjustments] = useState<BalanceAdjustment[]>(() => getInitialData('adjustments', []));
  const [marketingMsg, setMarketingMsg] = useState(() => getInitialData('marketing_msg', ""));
  const [campaignGoal, setCampaignGoal] = useState(() => getInitialData('campaign_goal', ""));

  const [selectedDate, setSelectedDate] = useState(() => getInitialData('selected_date', new Date().toISOString().split('T')[0]));
  const [reportMonth, setReportMonth] = useState(() => getInitialData('report_month', new Date().toISOString().substring(0, 7)));

  const [aptClientSearch, setAptClientSearch] = useState("");
  const [selectedAptClient, setSelectedAptClient] = useState<Client | null>(null);
  const [showAptResults, setShowAptResults] = useState(false);
  const [finishingAptId, setFinishingAptId] = useState<string | null>(null);
  const [isGeneratingMessage, setIsGeneratingMessage] = useState(false);
  const [isSendingReminder, setIsSendingReminder] = useState<string | null>(null);
  const [clientPhotoBase64, setClientPhotoBase64] = useState<string | null>(null);

  const [isPrivacyMode, setIsPrivacyMode] = useState(() => getInitialData('privacy_mode', false));
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  // Efeito Global de Persistência
  useEffect(() => {
    if (session && isAuthenticated) {
      setIsSaving(true);
      const userKey = session.username;

      const dataToSave: Record<string, any> = { 
        clients, services, materials, drinks, appointments, 
        adjustments, sales, marketing_msg: marketingMsg, 
        campaign_goal: campaignGoal, selected_date: selectedDate,
        report_month: reportMonth, privacy_mode: isPrivacyMode,
        active_tab: activeTab
      };

      Object.entries(dataToSave).forEach(([key, value]) => {
        StorageService.set(`${userKey}_${key}`, value);
      });

      const currentAuth = StorageService.get<any>(`user_auth_${userKey}`);
      if (currentAuth) {
        StorageService.set(`user_auth_${userKey}`, { ...currentAuth, ...session });
      }
      StorageService.set('session', session);

      const timer = setTimeout(() => setIsSaving(false), 800);
      return () => clearTimeout(timer);
    }
  }, [
    clients, services, materials, drinks, appointments, adjustments, 
    sales, marketingMsg, campaignGoal, selectedDate, reportMonth, 
    isPrivacyMode, activeTab, session, isAuthenticated
  ]);

  const stats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const monthPrefix = today.substring(0, 7);
    const yearPrefix = today.substring(0, 4);
    const selectedMonthPrefix = reportMonth;

    const compApts = appointments.filter(a => a.completed);

    const serviceMonthlyRev = compApts.filter(a => a.date.startsWith(monthPrefix) && a.paid).reduce((acc, a) => acc + a.finalPrice, 0);
    const salesMonthlyRev = sales.filter(s => s.date.startsWith(monthPrefix)).reduce((acc, s) => acc + s.price, 0);
    const adjustmentsMonthly = adjustments.filter(a => a.date.startsWith(monthPrefix)).reduce((acc, a) => acc + a.amount, 0);
    const monthlyRevTotal = serviceMonthlyRev + salesMonthlyRev + adjustmentsMonthly;

    const reportApts = compApts.filter(a => a.date.startsWith(selectedMonthPrefix));
    const reportSales = sales.filter(s => s.date.startsWith(selectedMonthPrefix));
    const reportAdjusts = adjustments.filter(a => a.date.startsWith(selectedMonthPrefix));

    const reportCutsCount = reportApts.length;
    const reportServiceRev = reportApts.filter(a => a.paid).reduce((acc, a) => acc + a.finalPrice, 0);
    const reportProductRev = reportSales.reduce((acc, s) => acc + s.price, 0);
    const reportAdjustRev = reportAdjusts.reduce((acc, a) => acc + a.amount, 0);
    const reportTotalRev = reportServiceRev + reportProductRev + reportAdjustRev;

    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

    const chartData = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const ds = d.toISOString().split('T')[0];
      const rev = compApts.filter(a => a.date === ds && a.paid).reduce((acc, a) => acc + a.finalPrice, 0) +
                  sales.filter(s => s.date === ds).reduce((acc, s) => acc + s.price, 0) +
                  adjustments.filter(a => a.date === ds).reduce((acc, a) => acc + a.amount, 0);
      return { name: d.toLocaleDateString('pt-BR', { weekday: 'short' }), receita: Math.max(0, rev) };
    });

    const monthlyReportData = Array.from({ length: 12 }, (_, i) => {
      const monthStr = `${yearPrefix}-${(i + 1).toString().padStart(2, '0')}`;
      const count = compApts.filter(a => a.date.startsWith(monthStr)).length;
      return {
        month: new Date(yearPrefix + '-' + (i + 1)).toLocaleString('pt-BR', { month: 'short' }).toUpperCase(),
        count: count
      };
    });

    return { 
      dailyRev: compApts.filter(a => a.date === today && a.paid).reduce((acc, a) => acc + a.finalPrice, 0) + sales.filter(s => s.date === today).reduce((acc, s) => acc + s.price, 0) + adjustments.filter(a => a.date === today).reduce((acc, a) => acc + a.amount, 0),
      monthlyRev: monthlyRevTotal, 
      todayCuts: compApts.filter(a => a.date === today).length,
      weekCuts: compApts.filter(a => new Date(a.date) >= sevenDaysAgo).length,
      monthlyCuts: compApts.filter(a => a.date.startsWith(monthPrefix)).length,
      yearlyCuts: compApts.filter(a => a.date.startsWith(yearPrefix)).length,
      reportCuts: reportCutsCount,
      reportRevenue: reportTotalRev,
      goalPercent: Math.min(Math.round((monthlyRevTotal / (session?.monthlyGoal || 5000)) * 100), 100),
      chartData,
      monthlyReportData
    };
  }, [appointments, services, sales, adjustments, session?.monthlyGoal, reportMonth]);

  const handleLogout = () => {
    StorageService.remove('session');
    setClients([]);
    setServices(DEFAULT_SERVICES);
    setAppointments([]);
    setAdjustments([]);
    setDrinks([]);
    setSales([]);
    setSession(null);
    setIsAuthenticated(false);
    setActiveTab(Tab.Dashboard);
  };

  const sendReminder = async (aptId: string) => {
    const apt = appointments.find(a => a.id === aptId);
    if (!apt) return;
    const client = clients.find(c => c.id === apt.clientId);
    const service = services.find(s => s.id === apt.serviceId);
    if (!client || !service) return;
    setIsSendingReminder(aptId);
    try {
      const msg = await GeminiService.generateBusinessMessage('reminder', client.name, service.name, apt.time);
      window.open(`https://wa.me/55${client.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
      showToast("Lembrete gerado com IA!");
    } catch (error) { showToast("Erro ao gerar lembrete", "error"); }
    finally { setIsSendingReminder(null); }
  };

  const toggleCompleteFlow = (id: string, paidStatus: boolean) => {
    setAppointments(prev => prev.map(apt => {
      if (apt.id === id) {
        if (paidStatus) {
           setClients(prevC => prevC.map(c => c.id === apt.clientId ? { ...c, totalSpent: c.totalSpent + apt.finalPrice } : c));
        }
        return { ...apt, completed: true, paid: paidStatus };
      }
      return apt;
    }));
    setFinishingAptId(null);
    showToast(paidStatus ? "Atendimento Pago!" : "Finalizado como Pendente!");
