                     )) : appointments.filter(a => a.completed && (financeSubTab === 'paid' ? a.paid : !a.paid)).map(apt => (
                        <div key={apt.id} className="p-6 bg-slate-900/40 border border-white/5 rounded-[32px] flex justify-between items-center group">
