                                 <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{apt.date} • {services.find(s => s.id === apt.serviceId)?.name}</p>
                              </div>
                           </div>
                           <div className="flex items-center gap-6">
                              <span className="text-xl font-black text-elite-cyan-400">{formatCurrency(apt.finalPrice)}</span>
