                  <div className="space-y-8">
                     <div className="flex justify-center">
                        <div className="h-32 w-32 rounded-[40px] border-4 border-elite-red-500 overflow-hidden shadow-2xl">
                           <img src={session?.profileImage} className="h-full w-full object-cover" />
                        </div>
                     </div>
                     <div className="space-y-6">
                        <Input label="NOME DA BARBEARIA" value={session?.shopName} onChange={e => setSession(s => s ? {...s, shopName: e.target.value} : null)} />
                        <Input label="WHATSAPP DE CONTATO" value={session?.phone} onChange={e => setSession(s => s ? {...s, phone: e.target.value} : null)} />
                        <Input label="META DE FATURAMENTO MENSAL (R$)" type="number" value={session?.monthlyGoal} onChange={e => setSession(s => s ? {...s, monthlyGoal: Number(e.target.value)} : null)} />
                     </div>
                     <div className="bg-elite-cyan-500/5 border border-elite-cyan-500/10 p-6 rounded-2xl">
                        <p className="text-[10px] font-black text-elite-cyan-400 uppercase tracking-widest text-center">As informações acima são salvas automaticamente.</p>
                     </div>
                  </div>
               </Card>
            </div>
          )}

          {activeTab === Tab.Services && (
            <div className="space-y-8 animate-in slide-in-from-right duration-500">
               <Card title="Serviços Oferecidos" icon={<Scissors size={18}/>}>
                  <form className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end" onSubmit={(e) => {
                     e.preventDefault();
                     const f = new FormData(e.target as HTMLFormElement);
                     setServices(prev => [...prev, { id: Date.now().toString(), name: f.get('n') as string, price: Number(f.get('p')), duration: 30 }]);
                     (e.target as HTMLFormElement).reset();
                     showToast("Serviço adicionado!");
                  }}>
                     <Input label="NOME DO SERVIÇO" name="n" placeholder="Corte degradê" required />
                     <Input label="VALOR (R$)" name="p" type="number" step="0.01" required />
                     <Button type="submit" className="w-full">ADICIONAR</Button>
                  </form>
               </Card>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {services.map(s => (
                    <div key={s.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[40px] hover:border-elite-red-500/30 transition-all shadow-xl group">
                       <div className="flex justify-between items-start mb-2">
                          <h4 className="text-lg font-black text-white uppercase tracking-tight">{s.name}</h4>
                          <button onClick={() => setServices(prev => prev.filter(x => x.id !== s.id))} className="text-slate-700 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                       </div>
                       <p className="text-3xl font-black text-elite-cyan-400">{formatCurrency(s.price)}</p>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {activeTab === Tab.Marketing && (
            <div className="space-y-8 animate-in fade-in duration-500">
               <Card title="Assistente de Marketing IA" icon={<Wand2 size={16}/>}>
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                     <div className="space-y-4">
                        <Input label="OBJETIVO DA CAMPANHA" value={campaignGoal} onChange={e => setCampaignGoal(e.target.value)} placeholder="Ex: Promoção de terça-feira corte + barba R$ 50" />
                        <Button variant="lilac" className="w-full py-4" onClick={async () => {
                           if(!campaignGoal) return showToast("Descreva o objetivo da campanha!", "info");
                           setIsGeneratingMessage(true);
                           const msg = await GeminiService.generateCampaignMessage(session?.shopName || 'Barbearia', campaignGoal);
                           setMarketingMsg(msg);
                           setIsGeneratingMessage(false);
                           showToast("Mensagem gerada!");
                        }} isLoading={isGeneratingMessage}><Sparkles size={16} className="mr-2"/> GERAR TEXTO IRRESISTÍVEL</Button>
                        <textarea className="w-full h-40 bg-slate-950/40 border border-white/10 rounded-2xl p-6 text-white text-xs font-medium focus:border-elite-red-500 outline-none transition-all shadow-inner" value={marketingMsg} onChange={e => setMarketingMsg(e.target.value)} placeholder="A mensagem da IA aparecerá aqui..." />
                     </div>
                     <div className="bg-slate-900/40 border border-white/5 rounded-[32px] p-6 shadow-xl">
                        <h4 className="font-black uppercase text-[10px] text-elite-cyan-400 mb-6 flex items-center gap-2 tracking-widest"><Users size={14}/> Enviar para Lista VIP</h4>
                        <div className="max-h-[300px] overflow-y-auto space-y-2 pr-2 custom-scrollbar">
                           {clients.map(c => (
                              <div key={c.id} className="flex items-center justify-between p-4 bg-slate-950/40 rounded-xl border border-white/5 group hover:border-emerald-500/30 transition-all">
                                 <span className="font-black text-[10px] text-white uppercase tracking-wider">{c.name}</span>
                                 <button onClick={() => {
                                    const msg = marketingMsg.replace('[NOME DO CLIENTE]', c.name);
                                    window.open(`https://wa.me/55${c.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
                                 }} className="p-2 text-emerald-500 hover:scale-125 transition-transform"><MessageCircle size={20}/></button>
                              </div>
                           ))}
                        </div>
                     </div>
                  </div>
               </Card>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { 
  LayoutDashboard, Calendar, Users, Scissors, 
  TrendingUp, Settings, LogOut, 
  Plus, CheckCircle2, DollarSign, Clock, Sparkles,
  Trash2, BellRing, Camera, User as UserIcon,
  Check, Undo2, AlertTriangle, Wallet, Receipt,
  MessageSquare, KeyRound, Smartphone, ShieldCheck,
  Edit3, Save, X, Send, Gift, Target, Zap, Box, Minus,
  Search, Phone, Image as ImageIcon, Briefcase,
  ExternalLink, Crown, Star, Eye, EyeOff, ShoppingCart, Link as LinkIcon,
  Megaphone, Wand2, MessageCircle, ChevronUp, ChevronDown, Activity, Beer, ArrowUpCircle, ArrowDownCircle,
  FileBarChart, History, PieChart, BarChart3, Filter, Upload, AlertCircle
} from 'lucide-react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, 
  Tooltip, ResponsiveContainer, BarChart, Bar
} from 'recharts';

import { Button, Input, Card, Badge } from './components/UI';
import { StorageService } from './services/storage';
import { GeminiService } from './services/gemini';
import { Client, Service, Appointment, UserSession, Tab, Material, Drink, Sale } from './types';

interface BalanceAdjustment {
  id: string;
  amount: number;
  reason: string;
  date: string;
}

const DEFAULT_SERVICES: Service[] = [
  { id: '1', name: 'Corte Social', price: 35, duration: 30 },
  { id: '2', name: 'Degradê Especial', price: 45, duration: 45 },
  { id: '3', name: 'Barba Terápia', price: 25, duration: 25 },
];

const DEFAULT_PROFILE_IMG = "https://images.unsplash.com/photo-1621605815971-fbc98d665033?q=80&w=400&h=400&auto=format&fit=crop";

const LogoElite = ({ className = "h-12 w-12" }: { className?: string }) => (
  <div className={`relative flex items-center justify-center ${className}`}>
    <div className="absolute inset-0 flex items-center justify-center">
      <Scissors className="text-elite-red-500 animate-scissors-left -translate-x-1" size={32} />
      <Scissors className="text-elite-red-500 animate-scissors-right translate-x-1" size={32} />
    </div>
  </div>
);

const App: React.FC = () => {
  const [session, setSession] = useState<UserSession | null>(() => StorageService.get<UserSession>('session'));
  const [isAuthenticated, setIsAuthenticated] = useState(!!session);
  const [authMode, setAuthMode] = useState<'login' | 'register' | 'reset'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const getInitialData = <T,>(key: string, defaultValue: T): T => {
    if (!session) return defaultValue;
    return StorageService.get<T>(`${session.username}_${key}`) || defaultValue;
  };

  const [activeTab, setActiveTab] = useState<Tab>(() => getInitialData('active_tab', Tab.Dashboard));
  const [financeSubTab, setFinanceSubTab] = useState<'paid' | 'pending' | 'adjustments'>('pending');

  const [clients, setClients] = useState<Client[]>(() => getInitialData('clients', []));
  const [services, setServices] = useState<Service[]>(() => getInitialData('services', DEFAULT_SERVICES));
  const [materials, setMaterials] = useState<Material[]>(() => getInitialData('materials', []));
  const [drinks, setDrinks] = useState<Drink[]>(() => getInitialData('drinks', []));
  const [sales, setSales] = useState<Sale[]>(() => getInitialData('sales', []));
  const [appointments, setAppointments] = useState<Appointment[]>(() => getInitialData('appointments', []));
  const [adjustments, setAdjustments] = useState<BalanceAdjustment[]>(() => getInitialData('adjustments', []));
  const [marketingMsg, setMarketingMsg] = useState(() => getInitialData('marketing_msg', ""));
  const [campaignGoal, setCampaignGoal] = useState(() => getInitialData('campaign_goal', ""));

  const [selectedDate, setSelectedDate] = useState(() => getInitialData('selected_date', new Date().toISOString().split('T')[0]));
  const [reportMonth, setReportMonth] = useState(() => getInitialData('report_month', new Date().toISOString().substring(0, 7)));

  const [aptClientSearch, setAptClientSearch] = useState("");
  const [selectedAptClient, setSelectedAptClient] = useState<Client | null>(null);
  const [showAptResults, setShowAptResults] = useState(false);
  const [finishingAptId, setFinishingAptId] = useState<string | null>(null);
  const [isGeneratingMessage, setIsGeneratingMessage] = useState(false);
  const [isSendingReminder, setIsSendingReminder] = useState<string | null>(null);
  const [clientPhotoBase64, setClientPhotoBase64] = useState<string | null>(null);

  // Estados para edição e duplicidade
  const [pendingClient, setPendingClient] = useState<{name: string, phone: string, photo: string | null} | null>(null);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [editPhotoBase64, setEditPhotoBase64] = useState<string | null>(null);

  const [isPrivacyMode, setIsPrivacyMode] = useState(() => getInitialData('privacy_mode', false));
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
    if (session && isAuthenticated) {
      setIsSaving(true);
      const userKey = session.username;

      const dataToSave: Record<string, any> = { 
        clients, services, materials, drinks, appointments, 
        adjustments, sales, marketing_msg: marketingMsg, 
        campaign_goal: campaignGoal, selected_date: selectedDate,
        report_month: reportMonth, privacy_mode: isPrivacyMode,
        active_tab: activeTab
      };

      Object.entries(dataToSave).forEach(([key, value]) => {
        StorageService.set(`${userKey}_${key}`, value);
      });

      const currentAuth = StorageService.get<any>(`user_auth_${userKey}`);
      if (currentAuth) {
        StorageService.set(`user_auth_${userKey}`, { ...currentAuth, ...session });
      }
      StorageService.set('session', session);

      const timer = setTimeout(() => setIsSaving(false), 800);
      return () => clearTimeout(timer);
    }
  }, [
    clients, services, materials, drinks, appointments, adjustments, 
    sales, marketingMsg, campaignGoal, selectedDate, reportMonth, 
    isPrivacyMode, activeTab, session, isAuthenticated
  ]);

  const stats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const monthPrefix = today.substring(0, 7);
    const yearPrefix = today.substring(0, 4);
    const selectedMonthPrefix = reportMonth;

    const compApts = appointments.filter(a => a.completed);

    const serviceMonthlyRev = compApts.filter(a => a.date.startsWith(monthPrefix) && a.paid).reduce((acc, a) => acc + a.finalPrice, 0);
    const salesMonthlyRev = sales.filter(s => s.date.startsWith(monthPrefix)).reduce((acc, s) => acc + s.price, 0);
    const adjustmentsMonthly = adjustments.filter(a => a.date.startsWith(monthPrefix)).reduce((acc, a) => acc + a.amount, 0);
    const monthlyRevTotal = serviceMonthlyRev + salesMonthlyRev + adjustmentsMonthly;

    const chartData = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const ds = d.toISOString().split('T')[0];
      const rev = compApts.filter(a => a.date === ds && a.paid).reduce((acc, a) => acc + a.finalPrice, 0) +
                  sales.filter(s => s.date === ds).reduce((acc, s) => acc + s.price, 0) +
                  adjustments.filter(a => a.date === ds).reduce((acc, a) => acc + a.amount, 0);
      return { name: d.toLocaleDateString('pt-BR', { weekday: 'short' }), receita: Math.max(0, rev) };
    });

    const monthlyReportData = Array.from({ length: 12 }, (_, i) => {
      const monthStr = `${yearPrefix}-${(i + 1).toString().padStart(2, '0')}`;
      const count = compApts.filter(a => a.date.startsWith(monthStr)).length;
      return {
        month: new Date(yearPrefix + '-' + (i + 1)).toLocaleString('pt-BR', { month: 'short' }).toUpperCase(),
        count: count
      };
    });

    return { 
      dailyRev: compApts.filter(a => a.date === today && a.paid).reduce((acc, a) => acc + a.finalPrice, 0) + sales.filter(s => s.date === today).reduce((acc, s) => acc + s.price, 0) + adjustments.filter(a => a.date === today).reduce((acc, a) => acc + a.amount, 0),
      monthlyRev: monthlyRevTotal, 
      todayCuts: compApts.filter(a => a.date === today).length,
      weekCuts: compApts.filter(a => new Date(a.date) >= sevenDaysAgo).length,
      monthlyCuts: compApts.filter(a => a.date.startsWith(monthPrefix)).length,
      yearlyCuts: compApts.filter(a => a.date.startsWith(yearPrefix)).length,
      reportCuts: compApts.filter(a => a.date.startsWith(reportMonth)).length,
      reportRevenue: compApts.filter(a => a.date.startsWith(reportMonth) && a.paid).reduce((acc, a) => acc + a.finalPrice, 0) + sales.filter(s => s.date.startsWith(reportMonth)).reduce((acc, s) => acc + s.price, 0) + adjustments.filter(a => a.date.startsWith(reportMonth)).reduce((acc, a) => acc + a.amount, 0),
      goalPercent: Math.min(Math.round((monthlyRevTotal / (session?.monthlyGoal || 5000)) * 100), 100),
      chartData,
      monthlyReportData
    };
  }, [appointments, services, sales, adjustments, session?.monthlyGoal, reportMonth]);

  const handleLogout = () => {
    StorageService.remove('session');
    setClients([]);
    setServices(DEFAULT_SERVICES);
    setAppointments([]);
    setAdjustments([]);
    setDrinks([]);
    setSales([]);
    setSession(null);
    setIsAuthenticated(false);
    setActiveTab(Tab.Dashboard);
  };

  const sendReminder = async (aptId: string) => {
    const apt = appointments.find(a => a.id === aptId);
    if (!apt) return;
    const client = clients.find(c => c.id === apt.clientId);
    const service = services.find(s => s.id === apt.serviceId);
    if (!client || !service) return;
    setIsSendingReminder(aptId);
    try {
      const msg = await GeminiService.generateBusinessMessage('reminder', client.name, service.name, apt.time);
      window.open(`https://wa.me/55${client.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
      showToast("Lembrete gerado com IA!");
    } catch (error) { showToast("Erro ao gerar lembrete", "error"); }
    finally { setIsSendingReminder(null); }
  };

  const toggleCompleteFlow = (id: string, paidStatus: boolean) => {
    setAppointments(prev => prev.map(apt => {
      if (apt.id === id) {
        if (paidStatus) {
           setClients(prevC => prevC.map(c => c.id === apt.clientId ? { ...c, totalSpent: c.totalSpent + apt.finalPrice } : c));
        }
        return { ...apt, completed: true, paid: paidStatus };
      }
      return apt;
    }));
    setFinishingAptId(null);
    showToast(paidStatus ? "Atendimento Pago!" : "Finalizado como Pendente!");
  };

  const sellDrink = (drink: Drink) => {
    if (drink.stock <= 0) return showToast("Sem estoque!", "error");
    setSales(prev => [...prev, { id: Date.now().toString(), itemId: drink.id, itemName: drink.name, price: drink.price, date: new Date().toISOString().split('T')[0] }]);
    setDrinks(prev => prev.map(d => d.id === drink.id ? { ...d, stock: d.stock - 1 } : d));
    showToast(`${drink.name} vendida!`);
  };

  const formatCurrency = (v: number) => isPrivacyMode ? '••••' : `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    const user = (f.get('username') as string)?.toLowerCase().trim();
    const pass = f.get('password') as string;

    if (authMode === 'register') {
      StorageService.set(`user_auth_${user}`, { username: user, password: pass, shopName: f.get('shopName'), phone: f.get('phone'), profileImage: DEFAULT_PROFILE_IMG, monthlyGoal: 5000 });
      setAuthMode('login');
      showToast("Conta criada com sucesso!");
      return;
    }

    if (authMode === 'reset') {
      const stored = StorageService.get<any>(`user_auth_${user}`);
      if (!stored) return setAuthError("Usuário não encontrado.");
      StorageService.set(`user_auth_${user}`, { ...stored, password: pass });
      setAuthMode('login');
      showToast("Senha alterada com sucesso!");
      setAuthError(null);
      return;
    }

    const stored = StorageService.get<any>(`user_auth_${user}`);
    if (!stored || stored.password !== pass) return setAuthError("Usuário ou senha incorretos.");
    const sess: UserSession = { shopName: stored.shopName, username: stored.username, phone: stored.phone, profileImage: stored.profileImage || DEFAULT_PROFILE_IMG, monthlyGoal: stored.monthlyGoal || 5000 };

    setClients(StorageService.get<Client[]>(`${sess.username}_clients`) || []);
    setServices(StorageService.get<Service[]>(`${sess.username}_services`) || DEFAULT_SERVICES);
    setAppointments(StorageService.get<Appointment[]>(`${sess.username}_appointments`) || []);
    setAdjustments(StorageService.get<BalanceAdjustment[]>(`${sess.username}_adjustments`) || []);
    setDrinks(StorageService.get<Drink[]>(`${sess.username}_drinks`) || []);
    setSales(StorageService.get<Sale[]>(`${sess.username}_sales`) || []);
    setMarketingMsg(StorageService.get<string>(`${sess.username}_marketing_msg`) || "");
    setCampaignGoal(StorageService.get<string>(`${sess.username}_campaign_goal`) || "");
    setSelectedDate(StorageService.get<string>(`${sess.username}_selected_date`) || new Date().toISOString().split('T')[0]);
    setReportMonth(StorageService.get<string>(`${sess.username}_report_month`) || new Date().toISOString().substring(0, 7));
    setIsPrivacyMode(StorageService.get<boolean>(`${sess.username}_privacy_mode`) || false);
    setActiveTab(StorageService.get<Tab>(`${sess.username}_active_tab`) || Tab.Dashboard);

    StorageService.set('session', sess);
    setSession(sess);
    setIsAuthenticated(true);
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>, isEdit: boolean = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (isEdit) setEditPhotoBase64(reader.result as string);
        else setClientPhotoBase64(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveNewClient = (name: string, phone: string, photo: string | null) => {
    setClients(prev => [...prev, { 
      id: Date.now().toString(), 
      name, 
      phone, 
      totalSpent: 0,
      photo: photo || undefined
    }]);
    setPendingClient(null);
    setClientPhotoBase64(null);
    showToast("Novo membro VIP!");
  };

  const handleClientSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    const name = f.get('n') as string;
    const phone = f.get('p') as string;

    const nameExists = clients.some(c => c.name.toLowerCase().trim() === name.toLowerCase().trim());

    if (nameExists) {
      setPendingClient({ name, phone, photo: clientPhotoBase64 });
      return;
    }

    saveNewClient(name, phone, clientPhotoBase64);
    (e.target as HTMLFormElement).reset();
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingClient) return;
    const f = new FormData(e.target as HTMLFormElement);
