  const [isAuthenticated, setIsAuthenticated] = useState(!!session);
  const [authMode, setAuthMode] = useState<'login' | 'register' | 'reset'>('login');
  const [authError, setAuthError] = useState<string | null>(null);

  const getInitialData = <T,>(key: string, defaultValue: T): T => {
    if (!session) return defaultValue;
    return StorageService.get<T>(`${session.username}_${key}`) || defaultValue;
  };

  const [activeTab, setActiveTab] = useState<Tab>(() => getInitialData('active_tab', Tab.Dashboard));
  const [financeSubTab, setFinanceSubTab] = useState<'paid' | 'pending' | 'adjustments'>('pending');

  const [clients, setClients] = useState<Client[]>(() => getInitialData('clients', []));
  const [services, setServices] = useState<Service[]>(() => getInitialData('services', DEFAULT_SERVICES));
  const [materials, setMaterials] = useState<Material[]>(() => getInitialData('materials', []));
  const [drinks, setDrinks] = useState<Drink[]>(() => getInitialData('drinks', []));
  const [sales, setSales] = useState<Sale[]>(() => getInitialData('sales', []));
  const [appointments, setAppointments] = useState<Appointment[]>(() => getInitialData('appointments', []));
  const [adjustments, setAdjustments] = useState<BalanceAdjustment[]>(() => getInitialData('adjustments', []));
  const [marketingMsg, setMarketingMsg] = useState(() => getInitialData('marketing_msg', ""));
  const [campaignGoal, setCampaignGoal] = useState(() => getInitialData('campaign_goal', ""));

  const [selectedDate, setSelectedDate] = useState(() => getInitialData('selected_date', new Date().toISOString().split('T')[0]));
  const [reportMonth, setReportMonth] = useState(() => getInitialData('report_month', new Date().toISOString().substring(0, 7)));

  const [aptClientSearch, setAptClientSearch] = useState("");
  const [selectedAptClient, setSelectedAptClient] = useState<Client | null>(null);
  const [showAptResults, setShowAptResults] = useState(false);
  const [finishingAptId, setFinishingAptId] = useState<string | null>(null);
  const [isGeneratingMessage, setIsGeneratingMessage] = useState(false);
  const [isSendingReminder, setIsSendingReminder] = useState<string | null>(null);
  const [clientPhotoBase64, setClientPhotoBase64] = useState<string | null>(null);

  // Estados para edição e duplicidade
  const [pendingClient, setPendingClient] = useState<{name: string, phone: string, photo: string | null} | null>(null);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [editPhotoBase64, setEditPhotoBase64] = useState<string | null>(null);

  const [isPrivacyMode, setIsPrivacyMode] = useState(() => getInitialData('privacy_mode', false));
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' | 'info' } | null>(null);
  const [isSaving, setIsSaving] = useState(false);

  const showToast = (message: string, type: 'success' | 'error' | 'info' = 'success') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 4000);
  };

  useEffect(() => {
    if (session && isAuthenticated) {
      setIsSaving(true);
      const userKey = session.username;

      const dataToSave: Record<string, any> = { 
        clients, services, materials, drinks, appointments, 
        adjustments, sales, marketing_msg: marketingMsg, 
        campaign_goal: campaignGoal, selected_date: selectedDate,
        report_month: reportMonth, privacy_mode: isPrivacyMode,
        active_tab: activeTab
      };

      Object.entries(dataToSave).forEach(([key, value]) => {
        StorageService.set(`${userKey}_${key}`, value);
      });

      const currentAuth = StorageService.get<any>(`user_auth_${userKey}`);
      if (currentAuth) {
        StorageService.set(`user_auth_${userKey}`, { ...currentAuth, ...session });
      }
      StorageService.set('session', session);

      const timer = setTimeout(() => setIsSaving(false), 800);
      return () => clearTimeout(timer);
    }
  }, [
    clients, services, materials, drinks, appointments, adjustments, 
    sales, marketingMsg, campaignGoal, selectedDate, reportMonth, 
    isPrivacyMode, activeTab, session, isAuthenticated
  ]);

  const stats = useMemo(() => {
    const today = new Date().toISOString().split('T')[0];
    const monthPrefix = today.substring(0, 7);
    const yearPrefix = today.substring(0, 4);
    const selectedMonthPrefix = reportMonth;

    // Added definition for sevenDaysAgo to fix the 'Cannot find name' error
    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);

    const compApts = appointments.filter(a => a.completed);

    const serviceMonthlyRev = compApts.filter(a => a.date.startsWith(monthPrefix) && a.paid).reduce((acc, a) => acc + a.finalPrice, 0);
    const salesMonthlyRev = sales.filter(s => s.date.startsWith(monthPrefix)).reduce((acc, s) => acc + s.price, 0);
    const adjustmentsMonthly = adjustments.filter(a => a.date.startsWith(monthPrefix)).reduce((acc, a) => acc + a.amount, 0);
    const monthlyRevTotal = serviceMonthlyRev + salesMonthlyRev + adjustmentsMonthly;

    const chartData = Array.from({ length: 7 }, (_, i) => {
      const d = new Date();
      d.setDate(d.getDate() - (6 - i));
      const ds = d.toISOString().split('T')[0];
      const rev = compApts.filter(a => a.date === ds && a.paid).reduce((acc, a) => acc + a.finalPrice, 0) +
                  sales.filter(s => s.date === ds).reduce((acc, s) => acc + s.price, 0) +
                  adjustments.filter(a => a.date === ds).reduce((acc, a) => acc + a.amount, 0);
      return { name: d.toLocaleDateString('pt-BR', { weekday: 'short' }), receita: Math.max(0, rev) };
    });

    const monthlyReportData = Array.from({ length: 12 }, (_, i) => {
      const monthStr = `${yearPrefix}-${(i + 1).toString().padStart(2, '0')}`;
      const count = compApts.filter(a => a.date.startsWith(monthStr)).length;
      return {
        month: new Date(yearPrefix + '-' + (i + 1)).toLocaleString('pt-BR', { month: 'short' }).toUpperCase(),
        count: count
      };
    });

    return { 
      dailyRev: compApts.filter(a => a.date === today && a.paid).reduce((acc, a) => acc + a.finalPrice, 0) + sales.filter(s => s.date === today).reduce((acc, s) => acc + s.price, 0) + adjustments.filter(a => a.date === today).reduce((acc, a) => acc + a.amount, 0),
      monthlyRev: monthlyRevTotal, 
      todayCuts: compApts.filter(a => a.date === today).length,
      weekCuts: compApts.filter(a => new Date(a.date) >= sevenDaysAgo).length,
      monthlyCuts: compApts.filter(a => a.date.startsWith(monthPrefix)).length,
      yearlyCuts: compApts.filter(a => a.date.startsWith(yearPrefix)).length,
      reportCuts: compApts.filter(a => a.date.startsWith(reportMonth)).length,
      reportRevenue: compApts.filter(a => a.date.startsWith(reportMonth) && a.paid).reduce((acc, a) => acc + a.finalPrice, 0) + sales.filter(s => s.date.startsWith(reportMonth)).reduce((acc, s) => acc + s.price, 0) + adjustments.filter(a => a.date.startsWith(reportMonth)).reduce((acc, a) => acc + a.amount, 0),
      goalPercent: Math.min(Math.round((monthlyRevTotal / (session?.monthlyGoal || 5000)) * 100), 100),
      chartData,
      monthlyReportData
    };
  }, [appointments, services, sales, adjustments, session?.monthlyGoal, reportMonth]);

  const handleLogout = () => {
    StorageService.remove('session');
    setClients([]);
    setServices(DEFAULT_SERVICES);
    setAppointments([]);
    setAdjustments([]);
    setDrinks([]);
    setSales([]);
    setSession(null);
    setIsAuthenticated(false);
    setActiveTab(Tab.Dashboard);
  };

  const sendReminder = async (aptId: string) => {
    const apt = appointments.find(a => a.id === aptId);
    if (!apt) return;
    const client = clients.find(c => c.id === apt.clientId);
    const service = services.find(s => s.id === apt.serviceId);
    if (!client || !service) return;
    setIsSendingReminder(aptId);
    try {
      const msg = await GeminiService.generateBusinessMessage('reminder', client.name, service.name, apt.time);
      window.open(`https://wa.me/55${client.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
      showToast("Lembrete gerado com IA!");
    } catch (error) { showToast("Erro ao gerar lembrete", "error"); }
    finally { setIsSendingReminder(null); }
  };

  const toggleCompleteFlow = (id: string, paidStatus: boolean) => {
    setAppointments(prev => prev.map(apt => {
      if (apt.id === id) {
        if (paidStatus) {
           setClients(prevC => prevC.map(c => c.id === apt.clientId ? { ...c, totalSpent: c.totalSpent + apt.finalPrice } : c));
        }
        return { ...apt, completed: true, paid: paidStatus };
      }
      return apt;
    }));
    setFinishingAptId(null);
    showToast(paidStatus ? "Atendimento Pago!" : "Finalizado como Pendente!");
  };

  const sellDrink = (drink: Drink) => {
    if (drink.stock <= 0) return showToast("Sem estoque!", "error");
    setSales(prev => [...prev, { id: Date.now().toString(), itemId: drink.id, itemName: drink.name, price: drink.price, date: new Date().toISOString().split('T')[0] }]);
    setDrinks(prev => prev.map(d => d.id === drink.id ? { ...d, stock: d.stock - 1 } : d));
    showToast(`${drink.name} vendida!`);
  };

  const formatCurrency = (v: number) => isPrivacyMode ? '••••' : `R$ ${v.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`;

  const handleAuth = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    const user = (f.get('username') as string)?.toLowerCase().trim();
    const pass = f.get('password') as string;

    if (authMode === 'register') {
      StorageService.set(`user_auth_${user}`, { username: user, password: pass, shopName: f.get('shopName'), phone: f.get('phone'), profileImage: DEFAULT_PROFILE_IMG, monthlyGoal: 5000 });
      setAuthMode('login');
      showToast("Conta criada com sucesso!");
      return;
    }

    if (authMode === 'reset') {
      const stored = StorageService.get<any>(`user_auth_${user}`);
      if (!stored) return setAuthError("Usuário não encontrado.");
      StorageService.set(`user_auth_${user}`, { ...stored, password: pass });
      setAuthMode('login');
      showToast("Senha alterada com sucesso!");
      setAuthError(null);
      return;
    }

    const stored = StorageService.get<any>(`user_auth_${user}`);
    if (!stored || stored.password !== pass) return setAuthError("Usuário ou senha incorretos.");
    const sess: UserSession = { shopName: stored.shopName, username: stored.username, phone: stored.phone, profileImage: stored.profileImage || DEFAULT_PROFILE_IMG, monthlyGoal: stored.monthlyGoal || 5000 };

    setClients(StorageService.get<Client[]>(`${sess.username}_clients`) || []);
    setServices(StorageService.get<Service[]>(`${sess.username}_services`) || DEFAULT_SERVICES);
    setAppointments(StorageService.get<Appointment[]>(`${sess.username}_appointments`) || []);
    setAdjustments(StorageService.get<BalanceAdjustment[]>(`${sess.username}_adjustments`) || []);
    setDrinks(StorageService.get<Drink[]>(`${sess.username}_drinks`) || []);
    setSales(StorageService.get<Sale[]>(`${sess.username}_sales`) || []);
    setMarketingMsg(StorageService.get<string>(`${sess.username}_marketing_msg`) || "");
    setCampaignGoal(StorageService.get<string>(`${sess.username}_campaign_goal`) || "");
    setSelectedDate(StorageService.get<string>(`${sess.username}_selected_date`) || new Date().toISOString().split('T')[0]);
    setReportMonth(StorageService.get<string>(`${sess.username}_report_month`) || new Date().toISOString().substring(0, 7));
    setIsPrivacyMode(StorageService.get<boolean>(`${sess.username}_privacy_mode`) || false);
    setActiveTab(StorageService.get<Tab>(`${sess.username}_active_tab`) || Tab.Dashboard);

    StorageService.set('session', sess);
    setSession(sess);
    setIsAuthenticated(true);
  };

  const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>, isEdit: boolean = false) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        if (isEdit) setEditPhotoBase64(reader.result as string);
        else setClientPhotoBase64(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const saveNewClient = (name: string, phone: string, photo: string | null) => {
    setClients(prev => [...prev, { 
      id: Date.now().toString(), 
      name, 
      phone, 
      totalSpent: 0,
      photo: photo || undefined
    }]);
    setPendingClient(null);
    setClientPhotoBase64(null);
    showToast("Novo membro VIP!");
  };

  const handleClientSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const f = new FormData(e.target as HTMLFormElement);
    const name = f.get('n') as string;
    const phone = f.get('p') as string;

    const nameExists = clients.some(c => c.name.toLowerCase().trim() === name.toLowerCase().trim());

    if (nameExists) {
      setPendingClient({ name, phone, photo: clientPhotoBase64 });
      return;
    }

    saveNewClient(name, phone, clientPhotoBase64);
    (e.target as HTMLFormElement).reset();
  };

  const handleEditSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingClient) return;
    const f = new FormData(e.target as HTMLFormElement);
    const name = f.get('n') as string;
    const phone = f.get('p') as string;

    setClients(prev => prev.map(c => 
      c.id === editingClient.id 
        ? { ...c, name, phone, photo: editPhotoBase64 || c.photo } 
        : c
    ));

    setEditingClient(null);
    setEditPhotoBase64(null);
    showToast("Dados atualizados!");
  };

  if (!isAuthenticated) return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-slate-950">
      <div className="w-full max-w-md space-y-8 animate-in fade-in zoom-in duration-500">
        <div className="text-center">
          <LogoElite className="mx-auto h-24 w-24 mb-4" />
          <h2 className="text-3xl font-black text-white uppercase tracking-tighter italic leading-none">Barbershop<br/><span className="text-elite-red-500 text-4xl">Matheus Farias</span></h2>
        </div>
        <Card className="glass-card">
          <form className="space-y-4" onSubmit={handleAuth}>
            {authError && <p className="text-[10px] text-red-500 font-black uppercase text-center bg-red-500/10 p-2 rounded-lg">{authError}</p>}

            {authMode === 'register' && (
              <>
                <Input label="NOME DA BARBEARIA" name="shopName" placeholder="EX: BARBER SHOP" required />
                <Input label="WHATSAPP" name="phone" placeholder="(11) 99999-9999" required />
              </>
            )}

            <Input label="USUÁRIO" name="username" placeholder="admin" required />

            <Input 
              label={authMode === 'reset' ? "NOVA SENHA" : "SENHA"} 
              name="password" 
              type="password" 
              placeholder="••••••••" 
              required 
            />

            <Button type="submit" className="w-full py-4">
              {authMode === 'login' ? 'ACESSAR PAINEL' : authMode === 'register' ? 'FINALIZAR CADASTRO' : 'CONFIRMAR NOVA SENHA'}
            </Button>

            <div className="flex flex-col gap-3 mt-4">
              <button type="button" onClick={() => { setAuthMode(authMode === 'login' ? 'register' : 'login'); setAuthError(null); }} className="w-full text-[10px] text-slate-500 font-black uppercase tracking-widest hover:text-elite-red-500 transition-all">
                {authMode === 'login' ? 'CRIAR NOVA CONTA' : 'VOLTAR PARA LOGIN'}
              </button>

              {authMode === 'login' && (
                <button type="button" onClick={() => { setAuthMode('reset'); setAuthError(null); }} className="w-full text-[10px] text-slate-700 font-black uppercase tracking-widest hover:text-elite-cyan-500 transition-all">
                  ESQUECI MINHA SENHA
                </button>
              )}
            </div>
          </form>
        </Card>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen text-slate-100 flex overflow-hidden bg-slate-950">
      {/* Edição de Cliente Modal */}
      {editingClient && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md animate-in fade-in duration-300">
          <div className="w-full max-w-lg">
            <Card title="Editar Dados do Cliente" icon={<Edit3 size={18}/>} actions={<button onClick={() => {setEditingClient(null); setEditPhotoBase64(null);}} className="text-slate-500 hover:text-white"><X size={20}/></button>}>
              <form className="space-y-6" onSubmit={handleEditSubmit}>
                <div className="flex justify-center mb-4">
                  <div className="relative group">
                    <div className="h-24 w-24 rounded-3xl border-2 border-elite-red-500 overflow-hidden shadow-2xl">
                       <img src={editPhotoBase64 || editingClient.photo || "https://images.unsplash.com/photo-1633332755192-727a05c4013d?q=80&w=200"} className="h-full w-full object-cover" />
                    </div>
                    <label className="absolute inset-0 flex items-center justify-center bg-black/50 opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer rounded-3xl">
                       <Camera className="text-white" size={24}/>
                       <input type="file" className="hidden" accept="image/*" onChange={(e) => handlePhotoChange(e, true)} />
                    </label>
                  </div>
                </div>
                <Input label="NOME COMPLETO" name="n" defaultValue={editingClient.name} required />
                <Input label="WHATSAPP" name="p" defaultValue={editingClient.phone} required />
                <div className="flex gap-2 pt-4">
                   <Button type="submit" variant="success" className="flex-1">SALVAR ALTERAÇÕES</Button>
                   <Button type="button" variant="ghost" className="flex-1" onClick={() => {setEditingClient(null); setEditPhotoBase64(null);}}>CANCELAR</Button>
                </div>
              </form>
            </Card>
          </div>
        </div>
      )}

      <aside className={`fixed inset-y-0 left-0 z-50 w-64 bg-slate-950/80 backdrop-blur-2xl border-r border-white/5 transition-all duration-300 lg:relative ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:w-20 lg:translate-x-0'}`}>
        <div className="h-full flex flex-col p-6">
          <div className="mb-8 flex items-center gap-4 overflow-hidden">
            <LogoElite className="h-10 w-10 min-w-[40px]" />
            {isSidebarOpen && <div className="truncate"><h1 className="text-[10px] font-black text-white uppercase tracking-widest">Matheus Farias</h1><p className="text-[8px] text-elite-red-500 font-black uppercase truncate">{session?.shopName}</p></div>}
          </div>
          <nav className="flex-1 space-y-1 overflow-y-auto pr-2 custom-scrollbar">
            {[
              { id: Tab.Dashboard, icon: LayoutDashboard, label: 'Painel' },
              { id: Tab.Agenda, icon: Calendar, label: 'Agenda' },
              { id: Tab.Clients, icon: Users, label: 'Clientes' },
              { id: Tab.Finance, icon: TrendingUp, label: 'Financeiro' },
              { id: Tab.Reports, icon: FileBarChart, label: 'Relatórios' },
              { id: Tab.Marketing, icon: Megaphone, label: 'Marketing AI' },
              { id: Tab.Services, icon: Scissors, label: 'Serviços' },
              { id: Tab.Drinks, icon: Beer, label: 'Bar' },
              { id: Tab.Inventory, icon: Box, label: 'Estoque' },
              { id: Tab.Profile, icon: Settings, label: 'Perfil' },
            ].map(item => (
              <button key={item.id} onClick={() => setActiveTab(item.id)} className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === item.id ? 'bg-elite-red-500 text-white shadow-lg' : 'text-slate-500 hover:text-elite-red-500 hover:bg-white/5'}`}>
                <item.icon size={16} />
                {isSidebarOpen && <span>{item.label}</span>}
              </button>
            ))}
          </nav>
          <button onClick={handleLogout} className="mt-6 flex items-center gap-3 px-4 py-3 text-[10px] font-black uppercase text-red-500 hover:bg-red-500/10 rounded-xl transition-all">
            <LogOut size={16} />
            {isSidebarOpen && <span>Sair</span>}
          </button>
        </div>
      </aside>

      <main className="flex-1 h-screen overflow-y-auto">
        <header className="sticky top-0 z-40 bg-slate-950/60 backdrop-blur-xl border-b border-white/5 px-8 py-4 flex items-center justify-between">
           <div className="flex items-center gap-4">
              <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="p-2 text-slate-500 hover:text-white lg:hidden"><LayoutDashboard size={18}/></button>
              <h2 className="text-sm font-black uppercase tracking-widest text-white">{activeTab}</h2>
           </div>
           <div className="flex items-center gap-4">
              {isSaving && <Badge variant="cyan" className="animate-pulse">SALVANDO...</Badge>}
              <button onClick={() => setIsPrivacyMode(!isPrivacyMode)} className="p-2 bg-slate-900 border border-white/5 rounded-lg text-slate-400 hover:text-elite-cyan-400 transition-all">
                {isPrivacyMode ? <EyeOff size={16}/> : <Eye size={16}/>}
              </button>
              <div className="h-8 w-8 rounded-lg border border-elite-red-500/30 bg-slate-900 flex items-center justify-center overflow-hidden">
                 <img src={session?.profileImage} className="h-full w-full object-cover" />
              </div>
           </div>
        </header>

        <div className="p-8 max-w-7xl mx-auto space-y-8 pb-32">
          {toast && (
            <div className={`fixed bottom-10 right-10 z-[100] px-6 py-4 rounded-2xl text-[10px] font-black uppercase flex items-center gap-3 animate-in slide-in-from-right duration-300 shadow-2xl ${toast.type === 'error' ? 'bg-red-600 text-white' : 'bg-emerald-500 text-black'}`}>
              {toast.type === 'error' ? <AlertTriangle size={16}/> : <CheckCircle2 size={16}/>} {toast.message}
            </div>
          )}

          {activeTab === Tab.Agenda && (
            <div className="grid grid-cols-1 lg:grid-cols-4 gap-8 animate-in slide-in-from-bottom duration-500">
               <div className="lg:col-span-1">
                  <Card title="Agendar" icon={<Plus size={16}/>}>
                     <form className="space-y-4" onSubmit={(e) => {
                        e.preventDefault();
                        const f = new FormData(e.target as HTMLFormElement);
                        const date = f.get('d') as string;
                        const time = f.get('t') as string;
                        const customPrice = f.get('cp') ? Number(f.get('cp')) : null;
                        const serviceId = f.get('s') as string;
                        const service = services.find(sv => sv.id === serviceId);

                        const conflict = appointments.find(a => a.date === date && a.time === time && !a.completed);
                        if (conflict) return showToast("Este horário já está ocupado!", "error");
                        if (!selectedAptClient) return showToast("Selecione um cliente!", "error");

                        setAppointments(prev => [...prev, { 
                          id: Date.now().toString(), 
                          clientId: selectedAptClient.id, 
                          serviceId: serviceId, 
                          date, 
                          time, 
                          completed: false, 
                          paid: false,
                          finalPrice: customPrice !== null ? customPrice : (service?.price || 0)
                        }]);
                        setAptClientSearch("");
                        setSelectedAptClient(null);
                        showToast("Horário reservado!");
                     }}>
                        <Input label="DATA" name="d" type="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)} required />
                        <Input label="HORA" name="t" type="time" required />
                        <div className="space-y-1 relative">
                           <label className="text-[10px] font-black text-elite-cyan-400 uppercase ml-1">CLIENTE</label>
                           <div className="flex items-center gap-2">
                             {selectedAptClient && (
                               <div className="h-10 w-10 min-w-[40px] rounded-xl border-2 border-elite-red-500 overflow-hidden shadow-lg animate-in zoom-in duration-300">
                                 {selectedAptClient.photo ? (
                                   <img src={selectedAptClient.photo} className="h-full w-full object-cover" />
                                 ) : (
                                   <div className="h-full w-full bg-slate-900 flex items-center justify-center font-black text-elite-red-500 uppercase text-xs">
                                     {selectedAptClient.name.charAt(0)}
                                   </div>
                                 )}
                               </div>
                             )}
                             <input 
                               type="text" 
                               placeholder="Buscar..." 
                               className="w-full bg-slate-950/40 border border-white/10 rounded-xl px-4 py-3 text-white text-xs font-bold focus:border-elite-red-500 outline-none" 
                               value={aptClientSearch} 
                               onChange={(e) => { setAptClientSearch(e.target.value); setShowAptResults(true); if(selectedAptClient) setSelectedAptClient(null); }} 
                             />
                           </div>
                           {showAptResults && (
                              <div className="absolute z-50 left-0 right-0 mt-2 bg-slate-900 border border-white/10 rounded-xl shadow-2xl overflow-hidden max-h-[150px] overflow-y-auto">
                                 {clients.filter(c => c.name.toLowerCase().includes(aptClientSearch.toLowerCase())).map(c => (
                                    <button 
                                      key={c.id} 
                                      type="button" 
                                      className="w-full text-left px-4 py-3 hover:bg-white/10 flex items-center gap-3 transition-colors" 
                                      onClick={() => { setSelectedAptClient(c); setAptClientSearch(c.name); setShowAptResults(false); }}
