                  <div className="space-y-8">
                     <div className="flex justify-center">
                        <div className="h-32 w-32 rounded-[40px] border-4 border-elite-red-500 overflow-hidden shadow-2xl">
                           <img src={session?.profileImage} className="h-full w-full object-cover" />
                        </div>
                     </div>
                     <div className="space-y-6">
                        <Input label="NOME DA BARBEARIA" value={session?.shopName} onChange={e => setSession(s => s ? {...s, shopName: e.target.value} : null)} />
                        <Input label="WHATSAPP DE CONTATO" value={session?.phone} onChange={e => setSession(s => s ? {...s, phone: e.target.value} : null)} />
                        <Input label="META DE FATURAMENTO MENSAL (R$)" type="number" value={session?.monthlyGoal} onChange={e => setSession(s => s ? {...s, monthlyGoal: Number(e.target.value)} : null)} />
                     </div>
                     <div className="bg-elite-cyan-500/5 border border-elite-cyan-500/10 p-6 rounded-2xl">
                        <p className="text-[10px] font-black text-elite-cyan-400 uppercase tracking-widest text-center">As informações acima são salvas automaticamente.</p>
                     </div>
