                     <div key={d.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] shadow-xl group hover:border-elite-red-500/30 transition-all">
                        <div className="flex justify-between items-start mb-6">
                           <h4 className="text-lg font-black text-white uppercase leading-tight italic">{d.name}</h4>
                           <button onClick={(e) => handleDeleteDrink(e, d.id)} className="p-2 text-slate-800 hover:text-red-500 hover:bg-red-500/10 rounded-lg transition-all"><Trash2 size={16}/></button>
                        </div>
                        <div className="flex items-center justify-between mb-6">
                           <div>
                              <p className="text-2xl font-black text-elite-cyan-400">{formatCurrency(d.price)}</p>
                              <Badge variant={d.stock <= 5 ? 'danger' : 'info'}>{d.stock} UN NO ESTOQUE</Badge>
                           </div>
                           <div className="flex flex-col gap-1">
                              <button onClick={() => setDrinks(prev => prev.map(x => x.id === d.id ? {...x, stock: x.stock + 1} : x))} className="p-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-all"><Plus size={14}/></button>
                              <button onClick={() => setDrinks(prev => prev.map(x => x.id === d.id ? {...x, stock: Math.max(0, x.stock - 1)} : x))} className="p-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-all"><Minus size={14}/></button>
                           </div>
                        </div>
                        <Button variant="success" className="w-full" onClick={() => sellDrink(d)} disabled={d.stock <= 0}><ShoppingCart size={18} className="mr-2"/> VENDER AGORA</Button>
                     </div>
                  ))}
               </div>
            </div>
          )}

          {activeTab === Tab.Inventory && (
            <div className="space-y-8 animate-in fade-in duration-500">
               <Card title="Gestão de Insumos" icon={<Box size={16}/>}>
                  <form className="grid grid-cols-1 md:grid-cols-4 gap-6 items-end" onSubmit={(e) => {
                     e.preventDefault();
                     const f = new FormData(e.target as HTMLFormElement);
                     setMaterials(prev => [...prev, { id: Date.now().toString(), name: f.get('n') as string, quantity: Number(f.get('q')), minQuantity: Number(f.get('mq')), unit: 'un' }]);
                     (e.target as HTMLFormElement).reset();
                     showToast("Insumo cadastrado!");
                  }}>
                     <Input label="MATERIAL" name="n" placeholder="Lâminas/Golas/Capa" required />
                     <Input label="QTD ATUAL" name="q" type="number" required />
                     <Input label="ESTOQUE MÍNIMO" name="mq" type="number" required />
                     <Button type="submit" className="w-full">SALVAR NO ESTOQUE</Button>
                  </form>
               </Card>
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {materials.map(m => (
                     <div key={m.id} className={`p-8 rounded-[32px] border transition-all shadow-xl ${m.quantity <= m.minQuantity ? 'bg-red-500/5 border-red-500/20' : 'bg-slate-900/40 border-white/5'}`}>
                        <div className="flex justify-between items-start mb-6">
                           <h4 className="text-lg font-black text-white uppercase">{m.name}</h4>
                           <div className="flex gap-2">
                              <button onClick={() => setMaterials(prev => prev.map(x => x.id === m.id ? {...x, quantity: x.quantity + 1} : x))} className="p-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-all"><Plus size={14}/></button>
                              <button onClick={() => setMaterials(prev => prev.map(x => x.id === m.id ? {...x, quantity: Math.max(0, x.quantity - 1)} : x))} className="p-2 bg-slate-800 text-white rounded-lg hover:bg-slate-700 transition-all"><Minus size={14}/></button>
                              <button onClick={(e) => handleDeleteMaterial(e, m.id)} className="p-2 bg-slate-800/50 text-slate-500 hover:text-red-500 rounded-lg transition-all ml-1"><Trash2 size={14}/></button>
                           </div>
                        </div>
                        <div className="flex items-center justify-between">
                           <span className={`text-4xl font-black ${m.quantity <= m.minQuantity ? 'text-red-500' : 'text-elite-cyan-400'}`}>{m.quantity}</span>
                           <div className="text-right">
                              <p className="text-[8px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1">Mínimo Ideal</p>
                              <span className="text-sm font-black text-white">{m.minQuantity} {m.unit}</span>
                           </div>
                        </div>
                     </div>
                  ))}
               </div>
            </div>
          )}

          {activeTab === Tab.Profile && (
            <div className="max-w-2xl mx-auto space-y-8 animate-in fade-in duration-500">
               <Card title="Configurações do Perfil" icon={<Settings size={16}/>}>
                  <div className="space-y-8">
                     <div className="flex justify-center">
                        <div className="h-32 w-32 rounded-[40px] border-4 border-elite-red-500 overflow-hidden shadow-2xl">
                           <img src={session?.profileImage} className="h-full w-full object-cover" />
                        </div>
                     </div>
                     <div className="space-y-6">
                        <Input label="NOME DA BARBEARIA" value={session?.shopName} onChange={e => setSession(s => s ? {...s, shopName: e.target.value} : null)} />
                        <Input label="WHATSAPP DE CONTATO" value={session?.phone} onChange={e => setSession(s => s ? {...s, phone: e.target.value} : null)} />
                        <Input label="META DE FATURAMENTO MENSAL (R$)" type="number" value={session?.monthlyGoal} onChange={e => setSession(s => s ? {...s, monthlyGoal: Number(e.target.value)} : null)} />
                     </div>
                     <div className="bg-elite-cyan-500/5 border border-elite-cyan-500/10 p-6 rounded-2xl">
                        <p className="text-[10px] font-black text-elite-cyan-400 uppercase tracking-widest text-center">As informações acima são salvas automaticamente.</p>
                     </div>
                  </div>
               </Card>

               <Card title="Backup & Sincronização" icon={<Database size={16}/>}>
                  <div className="space-y-6">
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-wider leading-relaxed text-center">
                      Para usar em outros navegadores ou computadores, exporte o backup e importe-o no novo local.
                    </p>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                      <Button variant="cyan" className="w-full flex gap-2" onClick={handleExportData}>
                        <Download size={16}/> EXPORTAR BACKUP
                      </Button>
                      <div className="relative">
                        <Button variant="secondary" className="w-full flex gap-2">
                           <Upload size={16}/> IMPORTAR BACKUP
                        </Button>
                        <input 
                          type="file" 
                          className="absolute inset-0 opacity-0 cursor-pointer" 
                          accept=".json" 
                          onChange={handleImportData}
                        />
                      </div>
                    </div>
                  </div>
               </Card>
            </div>
          )}

          {activeTab === Tab.Reports && (
            <div className="space-y-8 animate-in fade-in duration-500">
               <div className="bg-slate-900/40 border border-white/5 p-6 rounded-3xl flex items-center justify-between gap-6 flex-wrap shadow-xl">
                  <div className="flex items-center gap-3">
                     <div className="p-3 bg-elite-red-500/10 text-elite-red-500 rounded-xl"><Filter size={20}/></div>
                     <div>
                        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-widest leading-none mb-1">Análise Mensal</h4>
                        <p className="text-xs font-bold text-white uppercase">Selecione o período de interesse</p>
                     </div>
                  </div>
                  <input type="month" value={reportMonth} onChange={(e) => setReportMonth(e.target.value)} className="bg-slate-950 border border-white/10 rounded-xl px-6 py-3 text-white text-xs font-black uppercase outline-none focus:border-elite-red-500 transition-all"/>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                  <div className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] shadow-xl">
                     <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Cortes Feitos</p>
                     <h3 className="text-4xl font-black text-white">{stats.reportCuts}</h3>
                  </div>
                  <div className="bg-emerald-500/5 border border-emerald-500/10 p-8 rounded-[32px] shadow-xl">
                     <p className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-1">Dinheiro Rendido</p>
                     <h3 className="text-4xl font-black text-white">{formatCurrency(stats.reportRevenue)}</h3>
                  </div>
                  <div className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] shadow-xl">
                     <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Produtividade Ano</p>
                     <h3 className="text-4xl font-black text-white">{stats.yearlyCuts}</h3>
                  </div>
                  <div className="bg-slate-900/40 border border-white/5 p-8 rounded-[32px] shadow-xl">
                     <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Atingimento Meta</p>
                     <h3 className="text-4xl font-black text-white">{stats.goalPercent}%</h3>
                  </div>
               </div>

               <Card title="Desempenho Semestral" className="shadow-2xl">
                  <div className="h-[300px] w-full">
                     <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={stats.monthlyReportData}>
                           <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#1e293b" />
                           <XAxis dataKey="month" axisLine={false} tickLine={false} tick={{fill: '#475569', fontSize: 10, fontWeight: 'bold'}} />
                           <Tooltip cursor={{fill: 'rgba(255,255,255,0.03)'}} contentStyle={{ backgroundColor: '#020617', border: '1px solid #1e293b', borderRadius: '12px' }} />
                           <Bar dataKey="count" fill="#ef4444" radius={[6, 6, 0, 0]} barSize={35} />
                        </BarChart>
                     </ResponsiveContainer>
                  </div>
               </Card>
            </div>
          )}

          {activeTab === Tab.Services && (
            <div className="space-y-8 animate-in slide-in-from-right duration-500">
               <Card title="Serviços Oferecidos" icon={<Scissors size={18}/>}>
                  <form className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end" onSubmit={(e) => {
                     e.preventDefault();
                     const f = new FormData(e.target as HTMLFormElement);
                     setServices(prev => [...prev, { id: Date.now().toString(), name: f.get('n') as string, price: Number(f.get('p')), duration: 30 }]);
                     (e.target as HTMLFormElement).reset();
                     showToast("Serviço adicionado!");
                  }}>
                     <Input label="NOME DO SERVIÇO" name="n" placeholder="Corte degradê" required />
                     <Input label="VALOR (R$)" name="p" type="number" step="0.01" required />
                     <Button type="submit" className="w-full">ADICIONAR SERVIÇO</Button>
                  </form>
               </Card>
               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                  {services.map(s => (
                    <div key={s.id} className="bg-slate-900/40 border border-white/5 p-8 rounded-[40px] hover:border-elite-red-500/30 transition-all shadow-xl group">
                       <div className="flex justify-between items-start mb-2">
                          <h4 className="text-lg font-black text-white uppercase tracking-tight">{s.name}</h4>
                          <button onClick={() => setServices(prev => prev.filter(x => x.id !== s.id))} className="text-slate-700 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                       </div>
                       <p className="text-3xl font-black text-elite-cyan-400">{formatCurrency(s.price)}</p>
                    </div>
                  ))}
               </div>
            </div>
          )}

          {activeTab === Tab.Marketing && (
            <div className="space-y-8 animate-in fade-in duration-500">
               <Card title="Assistente de Marketing IA" icon={<Wand2 size={16}/>}>
                  <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                     <div className="space-y-4">
                        <Input label="OBJETIVO DA CAMPANHA" value={campaignGoal} onChange={e => setCampaignGoal(e.target.value)} placeholder="Ex: Promoção de terça-feira corte + barba R$ 50" />
                        <Button variant="lilac" className="w-full py-4" onClick={async () => {
                           if(!campaignGoal) return showToast("Descreva o objetivo da campanha!", "info");
                           setIsGeneratingMessage(true);
                           const msg = await GeminiService.generateCampaignMessage(session?.shopName || 'Barbearia', campaignGoal);
                           setMarketingMsg(msg);
                           setIsGeneratingMessage(false);
                           showToast("Mensagem gerada!");
                        }} isLoading={isGeneratingMessage}><Sparkles size={16} className="mr-2"/> GERAR TEXTO IRRESISTÍVEL</Button>
                        <textarea className="w-full h-40 bg-slate-950/40 border border-white/10 rounded-2xl p-6 text-white text-xs font-medium focus:border-elite-red-500 outline-none transition-all shadow-inner" value={marketingMsg} onChange={e => setMarketingMsg(e.target.value)} placeholder="A mensagem da IA aparecerá aqui..." />
                     </div>
                     <div className="bg-slate-900/40 border border-white/5 rounded-[32px] p-6 shadow-xl">
                        <h4 className="font-black uppercase text-[10px] text-elite-cyan-400 mb-6 flex items-center gap-2 tracking-widest"><Users size={14}/> Enviar para Lista VIP</h4>
                        <div className="max-h-[300px] overflow-y-auto space-y-2 pr-2 custom-scrollbar">
                           {clients.map(c => (
                              <div key={c.id} className="flex items-center justify-between p-4 bg-slate-950/40 rounded-xl border border-white/5 group hover:border-emerald-500/30 transition-all">
                                 <span className="font-black text-[10px] text-white uppercase tracking-wider">{c.name}</span>
                                 <button onClick={() => {
                                    const msg = marketingMsg.replace('[NOME DO CLIENTE]', c.name);
                                    window.open(`https://wa.me/55${c.phone.replace(/\D/g,'')}?text=${encodeURIComponent(msg)}`, '_blank');
                                 }} className="p-2 text-emerald-500 hover:scale-125 transition-transform"><MessageCircle size={20}/></button>
                              </div>
                           ))}
                        </div>
                     </div>
                  </div>
               </Card>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;
